export default Hero;

import { useEffect, useState } from "react";
import { useNavigate, Outlet, Link, useLocation } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { useSessionTracking } from "@/hooks/useSessionTracking";
import {
  Calendar,
  Users,
  ClipboardList,
  LogOut,
  Home,
  Loader2,
  FolderKanban,
  Image,
  UserPlus,
  Shield,
  UserCog,
  Mail,
  BarChart3,
  BookOpen,
  AlertCircle,
  Menu,
  X,
  Activity,
  FileSpreadsheet,
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { ThemeToggle } from "./ThemeToggle";
import clubLogo from "@/assets/club-logo.png";
import {
  AppRole,
  CMS_ACCESS_ROLES,
  ROLE_PERMISSIONS,
  PAGE_PERMISSION_MAP
} from "@/contexts/RoleContext";

interface NavItem {
  path: string;
  icon: React.ComponentType<{ className?: string }>;
  label: string;
  permission: string; // Permission key required to access this
}

const AdminLayout = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const { toast } = useToast();
  const [loading, setLoading] = useState(true);
  const [hasAccess, setHasAccess] = useState(false);
  const [userRole, setUserRole] = useState<AppRole>(null);
  const [userEmail, setUserEmail] = useState<string>("");
  const [userName, setUserName] = useState<string>("");
  const [pendingRole, setPendingRole] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // Track user session activity for active users feature
  useSessionTracking();

  // Close sidebar when route changes (mobile)
  useEffect(() => {
    setSidebarOpen(false);
  }, [location.pathname]);

  // Prevent body scroll when sidebar is open on mobile
  useEffect(() => {
    if (sidebarOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => {
      document.body.style.overflow = 'unset';
    };
  }, [sidebarOpen]);

  useEffect(() => {
    checkAdminAccess();
  }, []);

  // Check page access when location changes
  useEffect(() => {
    if (hasAccess && userRole) {
      const canAccess = canAccessCurrentPage();
      if (!canAccess) {
        toast({
          title: "Access Denied",
          description: "You don't have permission to access this page.",
          variant: "destructive",
        });
        // Redirect to first accessible page
        const firstAccessible = getFirstAccessiblePage();
        if (firstAccessible) {
          navigate(firstAccessible);
        }
      }
    }
  }, [location.pathname, hasAccess, userRole]);

  const hasPermission = (permission: string): boolean => {
    if (!userRole) return false;
    if (userRole === 'admin') return true;

    const permissions = ROLE_PERMISSIONS[userRole] || [];
    return permissions.includes('all') || permissions.includes(permission);
  };

  const canAccessCurrentPage = (): boolean => {
    if (!userRole) return false;
    if (userRole === 'admin') return true;

    const permission = PAGE_PERMISSION_MAP[location.pathname];
    if (!permission) return true; // Allow access to undefined pages (index)

    return hasPermission(permission);
  };

  const getFirstAccessiblePage = (): string | null => {
    const navItems = getAllNavItems();
    for (const item of navItems) {
      if (hasPermission(item.permission)) {
        return item.path;
      }
    }
    return null;
  };

  const checkAdminAccess = async () => {
    try {
      const { data: { user } } = await supabase.auth.getUser();

      if (!user) {
        navigate("/admin/login");
        return;
      }

      setUserEmail(user.email || "");

      // Fetch user profile for name
      const { data: profile } = await supabase
        .from("profiles")
        .select("full_name")
        .eq("id", user.id)
        .single();

      if (profile?.full_name) {
        setUserName(profile.full_name);
      }

      // Check user_roles table for any CMS access role
      const { data: roleData } = await supabase
        .from("user_roles")
        .select("role")
        .eq("user_id", user.id)
        .single();

      if (roleData?.role && CMS_ACCESS_ROLES.includes(roleData.role as AppRole)) {
        setUserRole(roleData.role as AppRole);
        setHasAccess(true);
        setLoading(false);
        return;
      }

      // Also check users_management with roles table for extended role system
      const { data: mgmtData } = await supabase
        .from("users_management")
        .select("roles(name)")
        .eq("user_id", user.id)
        .single();

      const roleName = (mgmtData?.roles as { name: string } | null)?.name;

      if (roleName && CMS_ACCESS_ROLES.includes(roleName as AppRole)) {
        setUserRole(roleName as AppRole);
        setHasAccess(true);
        setLoading(false);
        return;
      }

      // Check if user exists but has no role
      if (!roleData && !mgmtData) {
        setPendingRole(true);
        setLoading(false);
        return;
      }

      // No valid CMS role found
      toast({
        title: "Access Denied",
        description: "You don't have permission to access the CMS.",
        variant: "destructive",
      });
      await supabase.auth.signOut();
      navigate("/admin/login");
    } catch (error) {
      console.error("Access check error:", error);
      navigate("/admin/login");
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    toast({
      title: "Logged out",
      description: "You have been logged out successfully.",
    });
    navigate("/admin/login");
  };

  const getAllNavItems = (): NavItem[] => [
    { path: "/admin/events", icon: Calendar, label: "Events", permission: 'events' },
    { path: "/admin/team", icon: Users, label: "Team", permission: 'team' },
    { path: "/admin/schedule", icon: ClipboardList, label: "Schedule", permission: 'schedule' },
    { path: "/admin/projects", icon: FolderKanban, label: "Projects", permission: 'projects' },
    { path: "/admin/gallery", icon: Image, label: "Gallery", permission: 'gallery' },
    { path: "/admin/blog", icon: BookOpen, label: "Blog", permission: 'blog' },
    { path: "/admin/enrollments", icon: UserPlus, label: "Enrollments", permission: 'enrollments' },
    { path: "/admin/users", icon: UserCog, label: "Users", permission: 'users' },
    { path: "/admin/roles", icon: Shield, label: "Roles & Permissions", permission: 'roles' },
    { path: "/admin/notifications", icon: Mail, label: "Notifications", permission: 'notifications' },
    { path: "/admin/analytics", icon: BarChart3, label: "Analytics", permission: 'analytics' },
    { path: "/admin/activity-log", icon: Activity, label: "Activity Log", permission: 'analytics' },
    { path: "/admin/import-export", icon: FileSpreadsheet, label: "Import / Export", permission: 'analytics' },
  ];

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );
  }

  // Show pending role message
  if (pendingRole) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-background px-4">
        <div className="max-w-md w-full text-center glass-card p-8 rounded-2xl">
          <div className="w-16 h-16 bg-amber-500/20 rounded-full flex items-center justify-center mx-auto mb-4">
            <AlertCircle className="w-8 h-8 text-amber-500" />
          </div>
          <h2 className="text-2xl font-bold mb-2">Pending Role Assignment</h2>
          <p className="text-muted-foreground mb-6">
            Your account is pending role assignment. Please contact an administrator to be assigned a role.
          </p>
          <p className="text-sm text-muted-foreground mb-6">
            Logged in as: <span className="font-medium">{userEmail}</span>
          </p>
          <div className="flex gap-3 justify-center">
            <Button variant="outline" onClick={handleLogout}>
              <LogOut className="w-4 h-4 mr-2" />
              Logout
            </Button>
            <Button onClick={() => navigate("/")}>
              <Home className="w-4 h-4 mr-2" />
              Go Home
            </Button>
          </div>
        </div>
      </div>
    );
  }

  if (!hasAccess) {
    return null;
  }

  // Filter nav items based on user role permissions
  const navItems = getAllNavItems().filter(item => hasPermission(item.permission));

  const getRoleBadgeColor = (role: AppRole) => {
    switch (role) {
      case 'admin':
        return 'bg-destructive/20 text-destructive';
      case 'editor':
        return 'bg-blue-500/20 text-blue-500';
      case 'coordinator':
        return 'bg-orange-500/20 text-orange-500';
      case 'content_creator':
        return 'bg-green-500/20 text-green-500';
      default:
        return 'bg-muted text-muted-foreground';
    }
  };

  const getRoleDisplayName = (role: AppRole) => {
    if (!role) return 'Unknown';
    return role.charAt(0).toUpperCase() + role.slice(1).replace('_', ' ');
  };

  const getInitials = (name: string) => {
    if (!name) return 'A';
    return name
      .split(' ')
      .map(part => part[0])
      .join('')
      .toUpperCase()
      .slice(0, 2);
  };

  const SidebarContent = () => (
    <>
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <div className="relative w-10 h-10 rounded-lg overflow-hidden shadow-lg ring-2 ring-primary/20">
            <img
              src={clubLogo}
              alt="Young Innovators Club Logo"
              className="w-full h-full object-cover"
            />
          </div>
          <div>
            <h2 className="font-bold gradient-text">CMS</h2>
            <p className="text-xs text-muted-foreground">Innovators Club</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <ThemeToggle />
          {/* Close button for mobile */}
          <button
            onClick={() => setSidebarOpen(false)}
            className="lg:hidden p-2 rounded-lg hover:bg-muted/50 transition-colors"
            aria-label="Close sidebar"
          >
            <X className="w-5 h-5" />
          </button>
        </div>
      </div>

      {/* User Profile Card */}
      <div className="mb-6 p-4 rounded-xl bg-gradient-to-br from-card to-muted/50 border border-primary/5 shadow-sm relative group overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-r from-primary/10 via-transparent to-secondary/10 opacity-0 group-hover:opacity-100 transition-opacity duration-500" />

        <div className="flex items-center gap-3 relative z-10">
          <div className="h-10 w-10 rounded-full bg-gradient-to-tr from-primary to-secondary p-[2px] shadow-md shrink-0">
            <div className="h-full w-full rounded-full bg-background flex items-center justify-center overflow-hidden">
              <span className="font-bold bg-gradient-to-r from-primary to-secondary bg-clip-text text-transparent text-xs sm:text-sm">
                {getInitials(userName)}
              </span>
            </div>
          </div>

          <div className="flex flex-col min-w-0">
            <p className="font-bold text-sm truncate text-foreground group-hover:text-primary transition-colors">
              {userName || 'User'}
            </p>
            <div className="flex items-center mt-0.5">
              <Shield className="w-3 h-3 mr-1 text-primary/70" />
              <span className="text-[10px] uppercase tracking-wider font-semibold text-muted-foreground">
                {getRoleDisplayName(userRole)}
              </span>
            </div>
          </div>
        </div>
      </div>

      <nav className="space-y-1.5 flex-1 overflow-y-auto">
        <Link to="/" onClick={() => setSidebarOpen(false)}>
          <Button
            variant="ghost"
            className="w-full justify-start gap-3"
          >
            <Home className="w-5 h-5" />
            Home Page
          </Button>
        </Link>

        {navItems.map((item) => (
          <Link key={item.path} to={item.path} onClick={() => setSidebarOpen(false)}>
            <Button
              variant={location.pathname === item.path ? "default" : "ghost"}
              className="w-full justify-start gap-3"
            >
              <item.icon className="w-5 h-5" />
              {item.label}
            </Button>
          </Link>
        ))}
      </nav>

      <div className="pt-4 mt-auto">
        <Button
          variant="outline"
          onClick={handleLogout}
          className="w-full justify-start gap-3"
        >
          <LogOut className="w-5 h-5" />
          Logout
        </Button>
      </div>
    </>
  );

  return (
    <div className="min-h-screen bg-background cms-theme">
      {/* Mobile Header */}
      <header className="lg:hidden fixed top-0 left-0 right-0 z-40 h-16 glass-card border-b border-border flex items-center justify-between px-4">
        <div className="flex items-center gap-3">
          <div className="relative w-8 h-8 rounded-lg overflow-hidden shadow ring-2 ring-primary/20">
            <img
              src={clubLogo}
              alt="CMS Logo"
              className="w-full h-full object-cover"
            />
          </div>
          <span className="font-bold gradient-text">CMS</span>
        </div>
        <button
          onClick={() => setSidebarOpen(true)}
          className="p-2.5 rounded-xl bg-gradient-to-br from-primary/10 to-secondary/10 hover:from-primary/20 hover:to-secondary/20 border border-primary/20 transition-all"
          aria-label="Open menu"
        >
          <Menu className="w-5 h-5 text-primary" />
        </button>
      </header>

      {/* Mobile Sidebar Overlay */}
      <div
        className={`fixed inset-0 z-50 lg:hidden transition-all duration-300 ${sidebarOpen ? "visible" : "invisible pointer-events-none"
          }`}
      >
        {/* Backdrop */}
        <div
          className={`absolute inset-0 backdrop-blur-sm bg-background/80 transition-opacity duration-300 ${sidebarOpen ? "opacity-100" : "opacity-0"
            }`}
          onClick={() => setSidebarOpen(false)}
        />

        {/* Sidebar Panel */}
        <aside
          className={`absolute left-0 top-0 h-full w-72 sm:w-80 glass-card border-r border-border flex flex-col p-6 transition-transform duration-300 ease-out ${sidebarOpen ? "translate-x-0" : "-translate-x-full"
            }`}
        >
          <SidebarContent />
        </aside>
      </div>

      {/* Desktop Sidebar - Fixed */}
      <aside className="hidden lg:flex fixed left-0 top-0 h-full w-64 glass-card border-r border-border flex-col p-6">
        <SidebarContent />
      </aside>

      {/* Main Content */}
      <main className="lg:ml-64 pt-16 lg:pt-0 min-h-screen">
        <div className="p-4 sm:p-6 lg:p-8">
          <Outlet />
        </div>
      </main>
    </div>
  );
};

export default AdminLayout;

import { motion, useMotionValue, useSpring, useTransform } from 'framer-motion';
import { Link } from 'react-router-dom';
import { Calendar, User, ArrowRight, Clock, Tag, Sparkles } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { format } from 'date-fns';
import { cn } from '@/lib/utils';

interface BlogCardProps {
  post: {
    id: string;
    title: string;
    slug: string;
    excerpt: string | null;
    author_name: string;
    author_image_url: string | null;
    cover_image_url: string | null;
    category: string | null;
    tags: string[] | null;
    published_at: string | null;
    reading_time_minutes: number | null;
    is_featured?: boolean;
  };
  index: number;
  featured?: boolean;
}

const BlogCard = ({ post, index, featured = false }: BlogCardProps) => {
  const x = useMotionValue(0);
  const y = useMotionValue(0);

  const mouseXSpring = useSpring(x);
  const mouseYSpring = useSpring(y);

  const rotateX = useTransform(mouseYSpring, [-0.5, 0.5], ["2.5deg", "-2.5deg"]);
  const rotateY = useTransform(mouseXSpring, [-0.5, 0.5], ["-2.5deg", "2.5deg"]);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const width = rect.width;
    const height = rect.height;
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;
    const xPct = mouseX / width - 0.5;
    const yPct = mouseY / height - 0.5;
    x.set(xPct);
    y.set(yPct);
  };

  const handleMouseLeave = () => {
    x.set(0);
    y.set(0);
  };

  const cardVariants = {
    hidden: { opacity: 0, y: 30 },
    visible: {
      opacity: 1,
      y: 0,
      transition: {
        duration: 0.8,
        delay: index * 0.1,
        ease: [0.16, 1, 0.3, 1] as any
      }
    }
  };

  const content = (
    <div className={cn(
      "relative h-full overflow-hidden transition-all duration-500",
      featured ? "rounded-[2rem] sm:rounded-[2.5rem]" : "rounded-2xl sm:rounded-3xl",
      "bg-background/40 backdrop-blur-[50px] backdrop-saturate-[180%] border border-white/10 shadow-2xl group",
      featured
        ? "min-h-[400px] sm:min-h-[500px] lg:min-h-[600px]"
        : "min-h-[350px] sm:min-h-[450px] lg:min-h-[500px]"
    )}>
      {/* Glow Effect */}
      <div className="absolute -inset-px bg-gradient-to-br from-primary/20 via-transparent to-accent/20 opacity-0 group-hover:opacity-100 transition-opacity duration-700 -z-10" />

      {/* Background Image with Parallax-ish Effect */}
      <div className="absolute inset-0 -z-20 overflow-hidden">
        {post.cover_image_url ? (
          <img
            src={post.cover_image_url}
            alt={post.title}
            className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110"
          />
        ) : (
          <div className="w-full h-full bg-gradient-to-br from-muted/50 to-muted" />
        )}
        <div className={cn(
          "absolute inset-0 bg-gradient-to-t transition-opacity duration-500",
          featured ? "from-background via-background/60 to-transparent" : "from-background via-background/80 to-background/20"
        )} />
      </div>

      {/* Card Body */}
      <div className="flex flex-col h-full p-6 sm:p-8 lg:p-10">
        <div className="flex flex-wrap gap-2 mb-6">
          {post.category && (
            <Badge className="bg-primary/20 backdrop-blur-md text-primary border-primary/20 hover:bg-primary/30 transition-colors py-1 px-4 text-xs font-bold uppercase tracking-wider">
              {post.category}
            </Badge>
          )}
          {featured && (
            <Badge className="bg-accent/20 backdrop-blur-md text-accent border-accent/20 py-1 px-4 text-xs font-bold uppercase tracking-wider">
              <Sparkles className="w-3 h-3 mr-1.5" /> Featured Story
            </Badge>
          )}
        </div>

        <div className="mt-auto space-y-4">
          <h2 className={cn(
            "font-black leading-tight tracking-tight text-white group-hover:text-primary transition-colors duration-300",
            featured ? "text-3xl sm:text-4xl md:text-5xl lg:text-6xl" : "text-xl sm:text-2xl md:text-3xl"
          )}>
            {post.title}
          </h2>

          {post.excerpt && (
            <p className={cn(
              "text-muted-foreground leading-relaxed line-clamp-2 transition-colors group-hover:text-foreground/90",
              featured ? "text-base sm:text-lg lg:text-xl max-w-2xl" : "text-sm sm:text-base"
            )}>
              {post.excerpt}
            </p>
          )}

          {/* Metadata Bar */}
          <div className="flex flex-wrap items-center gap-4 sm:gap-6 pt-4 sm:pt-6 mt-4 sm:mt-6 border-t border-white/5 text-[10px] sm:text-xs md:text-sm text-muted-foreground font-medium">
            <div className="flex items-center gap-2 sm:gap-3">
              <div className="h-8 w-8 sm:h-10 sm:w-10 rounded-full border border-white/10 overflow-hidden bg-white/5">
                {post.author_image_url ? (
                  <img src={post.author_image_url} alt={post.author_name} className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center bg-primary/10 text-primary text-[8px] sm:text-[10px]">PI</div>
                )}
              </div>
              <span>{post.author_name}</span>
            </div>

            <div className="flex items-center gap-1.5 sm:gap-2">
