  timestamp: string;
  icon: string;
}

interface RealtimeAnalyticsState {
  activeUsers: ActiveUser[];
  recentEvents: RealtimeEvent[];
  connectionStatus: "connecting" | "connected" | "disconnected" | "error";
  enrollmentCount: number;
  blogCount: number;
  eventCount: number;
}

export const useRealtimeAnalytics = () => {
  const [state, setState] = useState<RealtimeAnalyticsState>({
    activeUsers: [],
    recentEvents: [],
    connectionStatus: "connecting",
    enrollmentCount: 0,
    blogCount: 0,
    eventCount: 0,
  });

  const addRealtimeEvent = useCallback((event: Omit<RealtimeEvent, "id" | "timestamp">) => {
    const newEvent: RealtimeEvent = {
      ...event,
      id: crypto.randomUUID(),
      timestamp: new Date().toISOString(),
    };

    setState((prev) => ({
      ...prev,
      recentEvents: [newEvent, ...prev.recentEvents].slice(0, 50), // Keep last 50 events
    }));
  }, []);

  const fetchActiveUsers = useCallback(async () => {
    try {
      // Get sessions active in the last 15 minutes
      const fifteenMinutesAgo = new Date(Date.now() - 15 * 60 * 1000).toISOString();

      const { data: sessions, error } = await supabase
        .from("user_sessions")
        .select("id, user_id, last_activity_at, is_active")
        .eq("is_active", true)
        .gte("last_activity_at", fifteenMinutesAgo)
        .order("last_activity_at", { ascending: false });

      if (error) throw error;

      // Fetch profiles for active users
      const userIds = [...new Set(sessions?.map((s) => s.user_id) || [])];
      
      if (userIds.length > 0) {
        const { data: profiles } = await supabase
          .from("profiles")
          .select("id, full_name, avatar_url, email")
          .in("id", userIds);

        const profileMap = new Map(profiles?.map((p) => [p.id, p]) || []);

        const activeUsers: ActiveUser[] = (sessions || []).map((session) => ({
          ...session,
          profile: profileMap.get(session.user_id) || undefined,
        }));

        setState((prev) => ({ ...prev, activeUsers }));
      } else {
        setState((prev) => ({ ...prev, activeUsers: [] }));
      }
    } catch (error) {
      console.error("Error fetching active users:", error);
    }
  }, []);

  const fetchCounts = useCallback(async () => {
    try {
      const [enrollments, blogs, events] = await Promise.all([
        supabase.from("enrollment_submissions").select("id", { count: "exact", head: true }),
        supabase.from("blog_posts").select("id", { count: "exact", head: true }),
        supabase.from("events").select("id", { count: "exact", head: true }),
      ]);

      setState((prev) => ({
        ...prev,
        enrollmentCount: enrollments.count || 0,
        blogCount: blogs.count || 0,
        eventCount: events.count || 0,
      }));
    } catch (error) {
      console.error("Error fetching counts:", error);
    }
  }, []);

  useEffect(() => {
    let channel: RealtimeChannel | null = null;

    const setupRealtimeSubscriptions = async () => {
      // Initial data fetch
      await Promise.all([fetchActiveUsers(), fetchCounts()]);

      // Set up realtime channel
      channel = supabase
        .channel("analytics_realtime")
        .on(
          "postgres_changes",
          { event: "*", schema: "public", table: "user_sessions" },
          (payload) => {
            if (payload.eventType === "INSERT" || payload.eventType === "UPDATE") {
              fetchActiveUsers();
              addRealtimeEvent({
                type: "session",
                title: "User Activity",
                description: payload.eventType === "INSERT" ? "New session started" : "Session updated",
                icon: "≡ƒæñ",
              });
            }
          }
        )
        .on(
          "postgres_changes",
          { event: "INSERT", schema: "public", table: "enrollment_submissions" },
          (payload) => {
            setState((prev) => ({ ...prev, enrollmentCount: prev.enrollmentCount + 1 }));
            addRealtimeEvent({
              type: "enrollment",
              title: "New Enrollment",
              description: `${(payload.new as any).name || "Someone"} submitted an enrollment`,
              icon: "≡ƒô¥",
            });
          }
        )
        .on(
          "postgres_changes",
          { event: "*", schema: "public", table: "blog_posts" },
          (payload) => {
            if (payload.eventType === "INSERT") {
              setState((prev) => ({ ...prev, blogCount: prev.blogCount + 1 }));
              addRealtimeEvent({
                type: "blog",
                title: "New Blog Post",
                description: `"${(payload.new as any).title || "New post"}" was created`,
                icon: "≡ƒô░",
              });
            } else if (payload.eventType === "UPDATE" && (payload.new as any).status === "published") {
              addRealtimeEvent({
                type: "blog",
                title: "Blog Published",
                description: `"${(payload.new as any).title || "A post"}" was published`,
                icon: "≡ƒÄë",
              });
            }
          }
        )
        .on(
          "postgres_changes",
          { event: "INSERT", schema: "public", table: "events" },
          (payload) => {
            setState((prev) => ({ ...prev, eventCount: prev.eventCount + 1 }));
            addRealtimeEvent({
              type: "event",
              title: "New Event",
              description: `"${(payload.new as any).title || "New event"}" was added`,
              icon: "≡ƒôà",
            });
          }
        )
        .subscribe((status) => {
          if (status === "SUBSCRIBED") {
            setState((prev) => ({ ...prev, connectionStatus: "connected" }));
          } else if (status === "CLOSED") {
            setState((prev) => ({ ...prev, connectionStatus: "disconnected" }));
          } else if (status === "CHANNEL_ERROR") {
            setState((prev) => ({ ...prev, connectionStatus: "error" }));
          }
        });
    };

    setupRealtimeSubscriptions();

    // Refresh active users periodically
    const refreshInterval = setInterval(fetchActiveUsers, 30000); // Every 30 seconds

    return () => {
      clearInterval(refreshInterval);
      if (channel) {
        supabase.removeChannel(channel);
      }
    };
  }, [fetchActiveUsers, fetchCounts, addRealtimeEvent]);

  return state;
};

import React, { useEffect } from 'react';
import { getCSPPolicy } from './security';
import { initAntiDebug, destroyAntiDebug, setAdminBypass } from './antiDebug';

/**
 * Security middleware component that applies security headers and protections
 * to the React application
 */
export const SecurityProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  useEffect(() => {
    // Apply security headers via meta tags
    const metaTags = [
      {
        httpEquiv: 'Content-Security-Policy',
        content: getCSPPolicy()
      },
      {
        name: 'referrer',
        content: 'strict-origin-when-cross-origin'
      }
    ];

    metaTags.forEach(tagProps => {
      const existingTag = document.querySelector(
        `meta[${tagProps.httpEquiv ? 'http-equiv' : 'name'}="${tagProps.httpEquiv || tagProps.name}"]`
      );

      if (!existingTag) {
        const metaTag = document.createElement('meta');
        if (tagProps.httpEquiv) {
          metaTag.setAttribute('http-equiv', tagProps.httpEquiv);
        } else if (tagProps.name) {
          metaTag.setAttribute('name', tagProps.name);
        }
        metaTag.setAttribute('content', tagProps.content);
        document.head.appendChild(metaTag);
      }
    });

    // Initialize anti-debugging protections (production only, skipped for admins)
    initAntiDebug();

    return () => {
      destroyAntiDebug();
    };
  }, []);

  return <>{children}</>;
};

/** Call this from RoleContext or auth logic to set/clear admin bypass */
export { setAdminBypass };

export default SecurityProvider;

