                    <img
                      src={post.author_image_url}
                      alt={post.author_name}
                      className="w-10 h-10 rounded-full object-cover border-2 border-primary/20"
                    />
                  ) : (
                    <div className="w-10 h-10 rounded-full bg-primary/10 flex items-center justify-center">
                      <User className="h-5 w-5 text-primary" />
                    </div>
                  )}
                  <span className="font-medium text-foreground">{post.author_name}</span>
                </div>
                {post.published_at && (
                  <div className="flex items-center gap-2">
                    <Calendar className="h-4 w-4" />
                    <span>{format(new Date(post.published_at), "MMMM dd, yyyy")}</span>
                  </div>
                )}
                {post.reading_time_minutes && (
                  <div className="flex items-center gap-2">
                    <Clock className="h-4 w-4" />
                    <span>{post.reading_time_minutes} min read</span>
                  </div>
                )}
              </div>

              {/* Tags */}
              {post.tags && post.tags.length > 0 && (
                <div className="flex flex-wrap gap-2 mb-6 sm:mb-8">
                  {post.tags.map(tag => (
                    <Badge
                      key={tag}
                      variant="outline"
                      className="text-xs hover:bg-primary/10 transition-colors cursor-default"
                    >
                      {tag}
                    </Badge>
                  ))}
                </div>
              )}

              {/* Excerpt */}
              {post.excerpt && (
                <motion.div
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ delay: 0.2 }}
                  className="p-4 sm:p-6 rounded-2xl bg-muted/30 border border-border/50 mb-8"
                >
                  <div className="flex items-start gap-3">
                    <Sparkles className="h-5 w-5 text-primary shrink-0 mt-0.5" />
                    <p className="text-base sm:text-lg text-muted-foreground italic leading-relaxed">
                      {post.excerpt}
                    </p>
                  </div>
                </motion.div>
              )}

              {/* Tech Stack */}
              {post.tech_stack && post.tech_stack.length > 0 && (
                <div className="p-4 rounded-xl bg-muted/30 border border-border/50 mb-8">
                  <div className="flex items-center gap-2 mb-3 text-sm font-medium">
                    <Cpu className="h-4 w-4 text-primary" />
                    Tech Stack / Tools Used
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {post.tech_stack.map(tech => (
                      <Badge key={tech} variant="secondary" className="bg-primary/10">
                        {tech}
                      </Badge>
                    ))}
                  </div>
                </div>
              )}

              {/* Content with Reading Preferences */}
              <div
                className={cn(
                  "blog-content-enhanced",
                  getContentClasses()
                )}
                dangerouslySetInnerHTML={{ __html: processContent(post.content) }}
              />

              {/* Bottom Share */}
              <div className="mt-12 pt-8 border-t border-border/50">
                <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                  <p className="text-muted-foreground">
                    Enjoyed this article? Share it with others!
                  </p>
                  <ShareButton post={post} />
                </div>
              </div>

              {/* Related Posts */}
              <RelatedPosts posts={relatedPosts} />
            </motion.article>

            {/* Sidebar TOC */}
            <aside className="hidden lg:block w-72 shrink-0">
              <TableOfContents content={post.content} />
            </aside>
          </div>
        </div>
      </main>

      <Footer />
      <MobileTableOfContents content={post.content} />
      <FloatingReadingButton
        preferences={preferences}
        updatePreference={updatePreference}
        resetPreferences={resetPreferences}
        open={showMobilePrefs}
        onOpenChange={setShowMobilePrefs}
        isGlobalDark={isGlobalDark}
      />
      <BlogGuide onExplore={handleExplore} />
    </div>
  );
};

export default BlogPostPage;

import { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { ArrowLeft } from "lucide-react";
import { Loading } from "@/components/ui/loading";

interface Project {
  id: string;
  title: string;
  description: string | null;
  image_url: string | null;
  category: string | null;
}

const ProjectDetail = () => {
  const { id } = useParams();
  const [project, setProject] = useState<Project | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (id) {
      fetchProject();
    }
  }, [id]);

  const fetchProject = async () => {
    try {
      const { data, error } = await supabase
        .from("projects")
        .select("*")
        .eq("id", id)
        .maybeSingle();

      if (error) throw error;
      setProject(data);
    } catch (error) {
      console.error("Error fetching project:", error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <Loading size="lg" className="min-h-screen" />;
  }

  if (!project) {
    return (
      <div className="min-h-screen bg-gradient-to-b from-background via-background to-muted/20 flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-4xl font-bold mb-4">Project Not Found</h1>
          <p className="text-muted-foreground mb-8">The project you're looking for doesn't exist.</p>
          <Link to="/#projects">
            <Button variant="default" className="btn-glow">
              <ArrowLeft className="mr-2 h-4 w-4" />
              Back to Projects
            </Button>
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-b from-background via-background to-muted/20">
      <div className="container-custom py-12">
        <Link to="/#projects">
          <Button variant="ghost" className="mb-8">
            <ArrowLeft className="mr-2 h-4 w-4" />
            Back to Projects
          </Button>
        </Link>

        <div className="max-w-5xl mx-auto">
          {project.image_url && (
            <div className="relative h-96 rounded-lg overflow-hidden mb-8 glow-border animate-fade-up">
              <img
                src={project.image_url}
                alt={project.title}
                className="w-full h-full object-cover"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-background/80 to-transparent" />
            </div>
          )}

          <div className="space-y-6 animate-fade-up" style={{ animationDelay: "0.2s" }}>
            {project.category && (
              <Badge variant="secondary" className="text-lg px-4 py-1">
                {project.category}
              </Badge>
            )}

            <h1 className="text-4xl md:text-6xl font-bold gradient-text">
              {project.title}
            </h1>

            <div className="prose prose-lg prose-invert max-w-none mt-8">
              <p className="text-lg text-foreground leading-relaxed">
                {project.description || "No description available for this project."}
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProjectDetail;

import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Tables } from "@/integrations/supabase/types";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Progress } from "@/components/ui/progress";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import {
  BarChart3, TrendingUp, Users, Calendar, Eye, Sun, Moon, Coffee,
  Sparkles, FileText, Image, FolderOpen, UserCheck, Clock, Activity,
  ArrowUpRight, ArrowDownRight, Zap, Target, Award,
  PieChart, Layers, Bell, CheckCircle2, XCircle, AlertCircle,
  Wifi, WifiOff, Radio
} from "lucide-react";
import { Loading } from "@/components/ui/loading";
import { format, subDays, isToday, isYesterday, parseISO, formatDistanceToNow } from "date-fns";
import { useRealtimeAnalytics } from "@/hooks/useRealtimeAnalytics";

interface Analytics {
  totalEnrollments: number;
  pendingEnrollments: number;
  approvedEnrollments: number;
  rejectedEnrollments: number;
  totalEvents: number;
  upcomingEvents: number;
  totalProjects: number;
  featuredProjects: number;
  totalTeamMembers: number;
  totalBlogPosts: number;
  publishedPosts: number;
  draftPosts: number;
  totalGalleryItems: number;
  recentActivity: Tables<"analytics_events">[];
  enrollmentsByInterest: Record<string, number>;
  enrollmentsByGrade: Record<string, number>;
  recentEnrollments: Array<{
    name: string;
    email: string;
    interest: string;
    status: string;
    created_at: string;
  }>;
  todayEnrollments: number;
  weekEnrollments: number;
}

const Analytics = () => {
  const [analytics, setAnalytics] = useState<Analytics | null>(null);
  const [loading, setLoading] = useState(true);
  const [timeRange, setTimeRange] = useState("all");
  const [userName, setUserName] = useState<string>("");
  const [userRole, setUserRole] = useState<string>("");
  const [currentTime, setCurrentTime] = useState(new Date());

  // Real-time analytics hook
  const realtimeData = useRealtimeAnalytics();

  // Clock update effect
  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentTime(new Date());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  // Data refresh effect (polls every 30 seconds)
  useEffect(() => {
    fetchAnalytics();
    const interval = setInterval(fetchAnalytics, 30000);
    return () => clearInterval(interval);
  }, [timeRange]);

  useEffect(() => {
    fetchUserProfile();
  }, []);

  const fetchUserProfile = async () => {
    const { data: { user } } = await supabase.auth.getUser();
    if (user) {
      const [profileRes, roleRes] = await Promise.all([
        supabase.from("profiles").select("full_name").eq("id", user.id).single(),
        supabase.from("user_roles").select("role").eq("user_id", user.id).single()
      ]);
      if (profileRes.data?.full_name) {
        setUserName(profileRes.data.full_name);
      }
      if (roleRes.data?.role) {
        setUserRole(roleRes.data.role);
      }
    }
  };

  const fetchAnalytics = async () => {
    try {
      let enrollmentQuery = supabase.from("enrollment_submissions").select("*");
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      const weekAgo = subDays(new Date(), 7);

      if (timeRange !== "all") {
        const days = timeRange === "7d" ? 7 : timeRange === "30d" ? 30 : 90;
        const since = subDays(new Date(), days);
        enrollmentQuery = enrollmentQuery.gte("created_at", since.toISOString());
      }

      const [
        enrollmentsRes,
        eventsRes,
        upcomingEventsRes,
        projectsRes,
        featuredProjectsRes,
        teamRes,
        analyticsRes,
        blogRes,
        publishedBlogRes,
        galleryRes,
        todayEnrollmentsRes,
        weekEnrollmentsRes
      ] = await Promise.all([
        enrollmentQuery,
        supabase.from("events").select("id", { count: 'exact', head: true }),
        supabase.from("events").select("id", { count: 'exact', head: true }).gte("event_date", new Date().toISOString().split('T')[0]),
        supabase.from("projects").select("id", { count: 'exact', head: true }),
        supabase.from("projects").select("id", { count: 'exact', head: true }).eq("is_featured", true),
        supabase.from("team_members").select("id", { count: 'exact', head: true }),
        supabase.from("analytics_events").select("*").order("created_at", { ascending: false }).limit(30),
        supabase.from("blog_posts").select("id", { count: 'exact', head: true }),
        supabase.from("blog_posts").select("id", { count: 'exact', head: true }).eq("status", "published"),
        supabase.from("gallery_items").select("id", { count: 'exact', head: true }),
        supabase.from("enrollment_submissions").select("id", { count: 'exact', head: true }).gte("created_at", today.toISOString()),
        supabase.from("enrollment_submissions").select("id", { count: 'exact', head: true }).gte("created_at", weekAgo.toISOString())
      ]);

      if (enrollmentsRes.error) throw enrollmentsRes.error;

      const enrollments = enrollmentsRes.data || [];

      const enrollmentsByInterest = enrollments.reduce((acc, e) => {
        acc[e.interest] = (acc[e.interest] || 0) + 1;
        return acc;
      }, {} as Record<string, number>);

      const enrollmentsByGrade = enrollments.reduce((acc, e) => {
        acc[e.grade] = (acc[e.grade] || 0) + 1;
        return acc;
      }, {} as Record<string, number>);

      const recentEnrollments = enrollments
        .sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime())
        .slice(0, 10)
        .map(e => ({
          name: e.name,
          email: e.email,
          interest: e.interest,
          status: e.status || 'pending',
          created_at: e.created_at
        }));

      setAnalytics({
        totalEnrollments: enrollments.length,
        pendingEnrollments: enrollments.filter(e => e.status === "pending").length,
        approvedEnrollments: enrollments.filter(e => e.status === "approved").length,
        rejectedEnrollments: enrollments.filter(e => e.status === "rejected").length,
        totalEvents: eventsRes.count || 0,
        upcomingEvents: upcomingEventsRes.count || 0,
        totalProjects: projectsRes.count || 0,
        featuredProjects: featuredProjectsRes.count || 0,
        totalTeamMembers: teamRes.count || 0,
        totalBlogPosts: blogRes.count || 0,
        publishedPosts: publishedBlogRes.count || 0,
        draftPosts: (blogRes.count || 0) - (publishedBlogRes.count || 0),
        totalGalleryItems: galleryRes.count || 0,
        recentActivity: analyticsRes.data || [],
        enrollmentsByInterest,
        enrollmentsByGrade,
        recentEnrollments,
        todayEnrollments: todayEnrollmentsRes.count || 0,
        weekEnrollments: weekEnrollmentsRes.count || 0
      });
    } catch (error) {
      console.error("Error fetching analytics:", error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <Loading size="lg" className="h-64" />;
  if (!analytics) return <div className="p-8">No data available</div>;

  const getGreeting = () => {
    const hour = currentTime.getHours();
    if (hour < 12) return "Good Morning";
    if (hour < 18) return "Good Afternoon";
    return "Good Evening";
  };

  const getTimeIcon = () => {
    const hour = currentTime.getHours();
    if (hour < 12) return <Sun className="w-8 h-8 text-orange-400" />;
    if (hour < 18) return <Coffee className="w-8 h-8 text-amber-600" />;
    return <Moon className="w-8 h-8 text-indigo-400" />;
  };

  const formatRelativeTime = (dateStr: string) => {
    const date = parseISO(dateStr);
    if (isToday(date)) return `Today at ${format(date, 'h:mm a')}`;
    if (isYesterday(date)) return `Yesterday at ${format(date, 'h:mm a')}`;
    return format(date, 'MMM d, h:mm a');
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'approved': return <CheckCircle2 className="w-4 h-4 text-green-500" />;
      case 'rejected': return <XCircle className="w-4 h-4 text-red-500" />;
      default: return <AlertCircle className="w-4 h-4 text-yellow-500" />;
    }
  };

  const getEventIcon = (type: string) => {
    switch (type) {
      case 'enrollment': return <UserCheck className="w-4 h-4" />;
      case 'blog': return <FileText className="w-4 h-4" />;
      case 'event': return <Calendar className="w-4 h-4" />;
      case 'session': return <Users className="w-4 h-4" />;
      default: return <Activity className="w-4 h-4" />;
    }
  };

  const getConnectionStatusColor = () => {
    switch (realtimeData.connectionStatus) {
      case 'connected': return 'text-green-500';
      case 'connecting': return 'text-yellow-500';
      case 'disconnected': return 'text-red-500';
      case 'error': return 'text-red-500';
      default: return 'text-muted-foreground';
    }
  };

  const totalInterests = Object.values(analytics.enrollmentsByInterest).reduce((a, b) => a + b, 0);

  return (
    <div className="p-4 md:p-8 space-y-6 max-w-7xl mx-auto">
      {/* Hero Welcome Section */}
      <div className="relative overflow-hidden rounded-3xl bg-gradient-to-br from-primary/10 via-secondary/5 to-accent/10 p-6 md:p-10 border border-border/50 shadow-2xl">
        <div className="absolute top-0 right-0 w-96 h-96 bg-primary/20 rounded-full blur-3xl -z-10 animate-pulse" />
        <div className="absolute bottom-0 left-0 w-64 h-64 bg-secondary/20 rounded-full blur-3xl -z-10 animate-pulse" style={{ animationDelay: "1s" }} />
        <div className="absolute inset-0 bg-grid-white/5 [mask-image:radial-gradient(ellipse_at_center,transparent_20%,black)] -z-10" />

        <div className="relative z-10 flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6">
          <div className="flex-1">
            <div className="flex items-center gap-2 text-sm font-medium text-muted-foreground mb-3">
              <Calendar className="w-4 h-4" />
              {format(currentTime, 'EEEE, MMMM d, yyyy')}
              <Badge variant="outline" className="ml-2 capitalize">{userRole || 'Admin'}</Badge>
              {/* Connection status */}
              <Badge variant="outline" className={`ml-2 ${getConnectionStatusColor()}`}>
                {realtimeData.connectionStatus === 'connected' ? (
                  <><Wifi className="w-3 h-3 mr-1" /> Live</>
                ) : realtimeData.connectionStatus === 'connecting' ? (
                  <><Radio className="w-3 h-3 mr-1 animate-pulse" /> Connecting...</>
                ) : (
                  <><WifiOff className="w-3 h-3 mr-1" /> Offline</>
                )}
              </Badge>
            </div>

            <h1 className="text-3xl md:text-5xl font-bold mb-4 tracking-tight">
              <span className="bg-gradient-to-r from-primary via-secondary to-accent bg-clip-text text-transparent">
                {getGreeting()}
              </span>
              <span className="text-foreground">, {userName ? userName.split(' ')[0] : 'Admin'}!</span>
            </h1>

            <p className="text-lg text-muted-foreground max-w-2xl leading-relaxed">
              Here's your club overview. You have <span className="text-primary font-semibold">{analytics.pendingEnrollments}</span> pending enrollments
              and <span className="text-primary font-semibold">{analytics.upcomingEvents}</span> upcoming events.
            </p>

            <div className="flex flex-wrap gap-3 mt-6">
              <Button variant="outline" className="gap-2" asChild>
                <a href="/admin/enrollments">
                  <Bell className="w-4 h-4" />
                  View Enrollments
                </a>
              </Button>
            </div>
          </div>

          <div className="hidden lg:flex flex-col items-center gap-4">
            <div className="w-24 h-24 rounded-3xl bg-gradient-to-br from-background/80 to-background/40 backdrop-blur-xl border border-border/50 flex items-center justify-center shadow-xl transform rotate-3 hover:rotate-6 transition-all duration-300">
              {getTimeIcon()}
            </div>
            <div className="text-center">
              <div className="text-3xl font-bold text-foreground tabular-nums">{format(currentTime, 'h:mm:ss')}</div>
              <div className="text-xs text-muted-foreground uppercase tracking-wider">{format(currentTime, 'a')}</div>
            </div>
          </div>
        </div>
      </div>

      {/* Quick Stats Row */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <Card className="relative overflow-hidden group hover:shadow-lg transition-all duration-300">
          <div className="absolute inset-0 bg-gradient-to-br from-blue-500/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
          <CardContent className="p-4 md:p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-xs md:text-sm text-muted-foreground font-medium">Today's Enrollments</p>
                <p className="text-2xl md:text-3xl font-bold text-foreground mt-1">{analytics.todayEnrollments}</p>
              </div>
              <div className="p-3 rounded-2xl bg-blue-500/10">
                <Zap className="w-5 h-5 md:w-6 md:h-6 text-blue-500" />
              </div>
            </div>
            <div className="flex items-center gap-1 mt-3 text-xs text-green-500">
              <ArrowUpRight className="w-3 h-3" />
              <span>{analytics.weekEnrollments} this week</span>
            </div>
          </CardContent>
        </Card>

        <Card className="relative overflow-hidden group hover:shadow-lg transition-all duration-300">
          <div className="absolute inset-0 bg-gradient-to-br from-amber-500/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
          <CardContent className="p-4 md:p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-xs md:text-sm text-muted-foreground font-medium">Pending Review</p>
                <p className="text-2xl md:text-3xl font-bold text-foreground mt-1">{analytics.pendingEnrollments}</p>
              </div>
              <div className="p-3 rounded-2xl bg-amber-500/10">
                <Clock className="w-5 h-5 md:w-6 md:h-6 text-amber-500" />
              </div>
            </div>
            <div className="flex items-center gap-1 mt-3 text-xs text-muted-foreground">
              <Target className="w-3 h-3" />
              <span>Needs attention</span>
            </div>
          </CardContent>
        </Card>

        <Card className="relative overflow-hidden group hover:shadow-lg transition-all duration-300">
          <div className="absolute inset-0 bg-gradient-to-br from-green-500/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
          <CardContent className="p-4 md:p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-xs md:text-sm text-muted-foreground font-medium">Active Users</p>
                <p className="text-2xl md:text-3xl font-bold text-foreground mt-1">{realtimeData.activeUsers.length}</p>
              </div>
              <div className="p-3 rounded-2xl bg-green-500/10">
                <Users className="w-5 h-5 md:w-6 md:h-6 text-green-500" />
              </div>
            </div>
            <div className="flex items-center gap-1 mt-3 text-xs text-green-500">
              <Radio className="w-3 h-3 animate-pulse" />
              <span>Online now</span>
            </div>
          </CardContent>
        </Card>

        <Card className="relative overflow-hidden group hover:shadow-lg transition-all duration-300">
          <div className="absolute inset-0 bg-gradient-to-br from-purple-500/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
          <CardContent className="p-4 md:p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-xs md:text-sm text-muted-foreground font-medium">Upcoming Events</p>
                <p className="text-2xl md:text-3xl font-bold text-foreground mt-1">{analytics.upcomingEvents}</p>
              </div>
              <div className="p-3 rounded-2xl bg-purple-500/10">
                <Calendar className="w-5 h-5 md:w-6 md:h-6 text-purple-500" />
              </div>
            </div>
            <div className="flex items-center gap-1 mt-3 text-xs text-muted-foreground">
              <Sparkles className="w-3 h-3" />
              <span>{analytics.totalEvents} total events</span>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Active Users & Live Activity Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Active Users Panel */}
        <Card>
          <CardHeader>
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Users className="w-5 h-5 text-green-500" />
                <CardTitle>Active Users</CardTitle>
              </div>
              <Badge variant="outline" className="text-green-500">
                <Radio className="w-3 h-3 mr-1 animate-pulse" /> {realtimeData.activeUsers.length} online
              </Badge>
            </div>
            <CardDescription>Currently active admins and editors</CardDescription>
          </CardHeader>
          <CardContent>
            <ScrollArea className="h-[200px]">
              <div className="space-y-3">
                {realtimeData.activeUsers.length > 0 ? (
                  realtimeData.activeUsers.map((user) => (
                    <div key={user.id} className="flex items-center gap-3 p-3 rounded-xl bg-muted/30 hover:bg-muted/50 transition-colors">
                      <div className="relative">
                        <Avatar className="h-10 w-10">
                          <AvatarImage src={user.profile?.avatar_url || undefined} />
                          <AvatarFallback className="bg-primary/10 text-primary">
                            {user.profile?.full_name?.charAt(0) || user.profile?.email?.charAt(0) || 'U'}
                          </AvatarFallback>
                        </Avatar>
                        <div className="absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full bg-green-500 border-2 border-background" />
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className="font-medium truncate">{user.profile?.full_name || 'Unknown User'}</p>
                        <p className="text-xs text-muted-foreground truncate">{user.profile?.email}</p>
                      </div>
                      <div className="text-xs text-muted-foreground">
                        {formatDistanceToNow(parseISO(user.last_activity_at), { addSuffix: true })}
                      </div>
                    </div>
                  ))
