                                                />

                                                <FormField
                                                    control={form.control}
                                                    name="tags"
                                                    render={({ field }) => (
                                                        <FormItem>
                                                            <FormLabel className="text-xs">Tags</FormLabel>
                                                            <FormControl>
                                                                <Input placeholder="AI, Innovation, Tech..." {...field} />
