];

const NotificationsManager = () => {
  const [enrollments, setEnrollments] = useState<Enrollment[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [loading, setLoading] = useState(true);
  const [sending, setSending] = useState(false);
  const [filter, setFilter] = useState<string>("all");
  const [formData, setFormData] = useState({ subject: "", message: "", recipient: "all" });
  const [sendResults, setSendResults] = useState<SendResult[]>([]);
  const [showResults, setShowResults] = useState(false);
  const [historySearch, setHistorySearch] = useState("");
  const { toast } = useToast();

  useEffect(() => {
    fetchData();
  }, [filter]);

  const fetchData = async () => {
    try {
      let query = supabase.from("enrollment_submissions").select("id, name, email, status");

      if (filter !== "all") {
        query = query.eq("status", filter);
      }

      const [enrollmentsRes, notificationsRes] = await Promise.all([
        query,
        supabase
          .from("enrollment_notifications")
          .select("*, enrollment_submissions(name, email)")
          .order("sent_at", { ascending: false })
          .limit(50)
      ]);

      if (enrollmentsRes.error) throw enrollmentsRes.error;
      if (notificationsRes.error) throw notificationsRes.error;

      setEnrollments(enrollmentsRes.data || []);
      setNotifications(notificationsRes.data || []);
    } catch (error) {
      const err = error as Error;
      toast({ title: "Error", description: err.message, variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  const applyTemplate = (templateId: string) => {
    const template = emailTemplates.find(t => t.id === templateId);
    if (template) {
      setFormData({
        ...formData,
        subject: template.subject,
        message: template.message
      });
    }
  };

  const handleSendNotification = async () => {
    if (!formData.subject || !formData.message) {
      toast({ title: "Error", description: "Subject and message are required", variant: "destructive" });
      return;
    }

    setSending(true);
    setSendResults([]);
    setShowResults(false);

    const results: SendResult[] = [];

    try {
      const targetEnrollments = formData.recipient === "all"
        ? enrollments
        : enrollments.filter(e => e.id === formData.recipient);

      if (targetEnrollments.length === 0) {
        toast({ title: "Error", description: "No recipients selected", variant: "destructive" });
        setSending(false);
        return;
      }

      const currentUser = await supabase.auth.getUser();

      // Send emails via edge function with individual error handling
      for (const enrollment of targetEnrollments) {
        try {
          // Replace {name} placeholder in message
          const personalizedMessage = formData.message.replace(/\{name\}/g, enrollment.name);

          const { data, error } = await supabase.functions.invoke("send-enrollment-update", {
            body: {
              email: enrollment.email,
              name: enrollment.name,
              subject: formData.subject,
              message: personalizedMessage
            }
          });

          if (error) {
            console.error(`Failed to send to ${enrollment.email}:`, error);
            results.push({
              email: enrollment.email,
              name: enrollment.name,
              success: false,
              error: error.message || "Failed to send email"
            });
          } else if (data?.error) {
            results.push({
              email: enrollment.email,
              name: enrollment.name,
              success: false,
              error: data.error
            });
          } else {
            // Log notification only on success
            await supabase.from("enrollment_notifications").insert({
              enrollment_id: enrollment.id,
              subject: formData.subject,
              message: personalizedMessage,
              sent_by: currentUser.data.user?.id
            });
            results.push({ email: enrollment.email, name: enrollment.name, success: true });
          }
        } catch (error) {
          const err = error as Error;
          results.push({
            email: enrollment.email,
            name: enrollment.name,
            success: false,
            error: err.message || "Unknown error"
          });
        }
      }

      setSendResults(results);
      setShowResults(true);

      const successCount = results.filter(r => r.success).length;
      const failCount = results.filter(r => !r.success).length;

      if (successCount > 0 && failCount === 0) {
        toast({
          title: "Success",
          description: `All ${successCount} email(s) sent successfully!`
        });
        setFormData({ subject: "", message: "", recipient: "all" });
      } else if (successCount > 0 && failCount > 0) {
        toast({
          title: "Partial Success",
          description: `${successCount} sent, ${failCount} failed. Check results below.`,
          variant: "destructive"
        });
      } else {
        toast({
          title: "Failed",
          description: "No emails were sent. Check results below.",
          variant: "destructive"
        });
      }

      fetchData();
    } catch (error) {
      const err = error as Error;
      toast({ title: "Error", description: err.message, variant: "destructive" });
    } finally {
      setSending(false);
    }
  };

  // Filter notifications by search
  const filteredNotifications = notifications.filter(n =>
    historySearch === "" ||
    n.subject.toLowerCase().includes(historySearch.toLowerCase()) ||
    n.enrollment_submissions?.name?.toLowerCase().includes(historySearch.toLowerCase()) ||
    n.enrollment_submissions?.email?.toLowerCase().includes(historySearch.toLowerCase())
  );

  if (loading) return <Loading size="lg" className="h-64" />;

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl sm:text-3xl font-bold flex items-center gap-2">
            <div className="p-2 rounded-xl bg-gradient-to-br from-primary/20 to-secondary/10">
              <Mail className="h-6 w-6 sm:h-8 sm:w-8 text-primary" />
            </div>
            Email Notifications
          </h1>
          <p className="text-muted-foreground mt-1">Send updates to enrolled students</p>
        </div>
        <div className="flex items-center gap-2">
          <Badge variant="outline" className="gap-1">
            <Users className="h-3 w-3" />
            {enrollments.length} Recipients
          </Badge>
        </div>
      </div>

      {/* Resend Domain Setup Notice */}
      <Alert className="border-primary/30 bg-gradient-to-r from-primary/5 to-secondary/5">
        <Info className="h-4 w-4" />
        <AlertTitle>Email Configuration</AlertTitle>
        <AlertDescription className="text-sm">
          External emails require a verified domain on{" "}
          <a href="https://resend.com/domains" target="_blank" rel="noopener noreferrer" className="text-primary underline hover:text-primary/80 transition-colors">
            Resend.com
          </a>.
        </AlertDescription>
      </Alert>

      <div className="grid gap-6 lg:grid-cols-3">
        {/* Left Column - Compose */}
        <div className="lg:col-span-2 space-y-6">
          <Card className="border-primary/10">
            <CardHeader className="pb-4">
              <CardTitle className="text-xl">Compose Email</CardTitle>
              <CardDescription>Create and send notifications to students</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              {/* Quick Templates */}
              <div>
                <label className="text-sm font-medium mb-2 block">Quick Templates</label>
                <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
                  {emailTemplates.map((template) => (
                    <button
                      key={template.id}
                      onClick={() => applyTemplate(template.id)}
                      className="flex items-center gap-2 p-3 rounded-xl border border-border hover:border-primary/50 hover:bg-primary/5 transition-all group text-left"
                    >
                      <div className="p-2 rounded-lg bg-primary/10 group-hover:bg-primary/20 transition-colors">
                        <template.icon className="h-4 w-4 text-primary" />
                      </div>
                      <span className="text-sm font-medium">{template.name}</span>
                    </button>
                  ))}
                </div>
              </div>

              {/* Recipient Selection */}
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                  <label className="text-sm font-medium mb-2 block">Filter by Status</label>
                  <Select value={filter} onValueChange={setFilter}>
                    <SelectTrigger>
                      <SelectValue placeholder="Filter by status" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="all">All Students</SelectItem>
                      <SelectItem value="pending">Pending</SelectItem>
                      <SelectItem value="approved">Approved</SelectItem>
                      <SelectItem value="rejected">Rejected</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <label className="text-sm font-medium mb-2 block">Recipient</label>
                  <Select value={formData.recipient} onValueChange={(value) => setFormData({ ...formData, recipient: value })}>
                    <SelectTrigger>
                      <SelectValue placeholder="Select recipient" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="all">All ({enrollments.length})</SelectItem>
                      {enrollments.map(e => (
                        <SelectItem key={e.id} value={e.id}>
                          {e.name} - {e.email}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              {/* Subject */}
              <div>
                <label className="text-sm font-medium mb-2 block">Subject</label>
                <Input
                  placeholder="Enter email subject..."
                  value={formData.subject}
                  onChange={(e) => setFormData({ ...formData, subject: e.target.value })}
                  className="border-primary/20 focus:border-primary"
                />
              </div>

              {/* Message */}
              <div>
                <div className="flex items-center justify-between mb-2">
                  <label className="text-sm font-medium">Message</label>
                  <span className="text-xs text-muted-foreground">
                    Use {"{name}"} for personalization
                  </span>
                </div>
                <Textarea
                  placeholder="Write your message... Use {name} to personalize for each recipient."
                  value={formData.message}
                  onChange={(e) => setFormData({ ...formData, message: e.target.value })}
                  rows={8}
                  className="border-primary/20 focus:border-primary resize-none"
                />
                <div className="flex justify-end mt-1">
                  <span className="text-xs text-muted-foreground">
                    {formData.message.length} characters
                  </span>
                </div>
              </div>

              {/* Send Button */}
              <Button
                onClick={handleSendNotification}
                disabled={sending || !formData.subject || !formData.message}
                className="w-full bg-gradient-to-r from-primary to-secondary hover:from-primary/90 hover:to-secondary/90 shadow-lg shadow-primary/25"
                size="lg"
              >
                {sending ? (
                  <>
                    <RefreshCw className="h-4 w-4 mr-2 animate-spin" />
                    Sending...
                  </>
                ) : (
                  <>
                    <Send className="h-4 w-4 mr-2" />
                    Send Notification
                  </>
                )}
              </Button>
            </CardContent>
          </Card>

          {/* Send Results */}
          {showResults && sendResults.length > 0 && (
            <Card className="border-primary/10">
              <CardHeader className="pb-3">
                <CardTitle className="text-lg flex items-center gap-2">
                  Send Results
                  <Badge variant="outline" className="ml-2">
                    {sendResults.filter(r => r.success).length}/{sendResults.length} Sent
                  </Badge>
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="max-h-64 overflow-y-auto space-y-2">
                  {sendResults.map((result, idx) => (
                    <div
                      key={idx}
                      className={`flex items-center justify-between p-3 rounded-xl border ${result.success
                          ? 'border-green-500/20 bg-green-500/5'
                          : 'border-destructive/20 bg-destructive/5'
                        }`}
                    >
                      <div className="flex items-center gap-3">
                        {result.success ? (
                          <CheckCircle className="h-5 w-5 text-green-500 flex-shrink-0" />
                        ) : (
                          <XCircle className="h-5 w-5 text-destructive flex-shrink-0" />
                        )}
                        <div className="min-w-0">
                          <p className="font-medium truncate">{result.name}</p>
                          <p className="text-xs text-muted-foreground truncate">{result.email}</p>
                        </div>
                      </div>
                      {result.success ? (
                        <Badge variant="outline" className="text-green-600 border-green-600 flex-shrink-0">Sent</Badge>
                      ) : (
                        <Badge variant="destructive" className="text-xs flex-shrink-0 max-w-[120px] truncate">
                          {result.error || "Failed"}
                        </Badge>
                      )}
                    </div>
                  ))}
                </div>
              </CardContent>
            </Card>
          )}
        </div>

        {/* Right Column - History */}
        <div className="lg:col-span-1">
          <Card className="border-primary/10 h-fit lg:sticky lg:top-20">
            <CardHeader className="pb-3">
              <CardTitle className="text-lg">Recent History</CardTitle>
              <div className="relative mt-2">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Search history..."
                  value={historySearch}
                  onChange={(e) => setHistorySearch(e.target.value)}
                  className="pl-9 h-9"
                />
              </div>
            </CardHeader>
            <CardContent>
              <div className="space-y-3 max-h-[500px] overflow-y-auto">
                {filteredNotifications.length === 0 ? (
                  <div className="text-center py-8 text-muted-foreground">
                    <Mail className="h-8 w-8 mx-auto mb-2 opacity-50" />
                    <p className="text-sm">No notifications found</p>
                  </div>
                ) : (
                  filteredNotifications.map((notification) => (
                    <div
                      key={notification.id}
                      className="p-3 rounded-xl border border-border hover:border-primary/20 transition-colors"
                    >
                      <div className="flex items-start justify-between gap-2 mb-2">
                        <p className="font-medium text-sm line-clamp-1">{notification.subject}</p>
                      </div>
                      <p className="text-xs text-muted-foreground line-clamp-2 mb-2">
                        {notification.message}
                      </p>
                      <div className="flex items-center justify-between text-xs">
                        <span className="text-muted-foreground">
                          {notification.enrollment_submissions?.name || "N/A"}
                        </span>
                        <span className="text-muted-foreground">
                          {new Date(notification.sent_at).toLocaleDateString()}
                        </span>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  );
};

export default NotificationsManager;

import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogDescription } from "@/components/ui/dialog";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import { Trash2, Edit, Shield, Plus, Database, RefreshCw, AlertCircle } from "lucide-react";
import { Loading } from "@/components/ui/loading";
import { Alert, AlertDescription } from "@/components/ui/alert";

interface Role {
  id: string;
  name: string;
  description: string;
  is_system_role: boolean;
  created_at: string;
}

interface Permission {
  id: string;
  resource: string;
  action: string;
  description: string;
}

// CMS Access permissions that should be available
const CMS_PERMISSIONS = [
  { resource: 'cms', action: 'access', description: 'Can access the CMS dashboard' },
  { resource: 'events', action: 'view', description: 'Can view events' },
  { resource: 'events', action: 'create', description: 'Can create events' },
  { resource: 'events', action: 'edit', description: 'Can edit events' },
  { resource: 'events', action: 'delete', description: 'Can delete events' },
  { resource: 'team', action: 'view', description: 'Can view team members' },
  { resource: 'team', action: 'create', description: 'Can create team members' },
  { resource: 'team', action: 'edit', description: 'Can edit team members' },
  { resource: 'team', action: 'delete', description: 'Can delete team members' },
  { resource: 'projects', action: 'view', description: 'Can view projects' },
  { resource: 'projects', action: 'create', description: 'Can create projects' },
  { resource: 'projects', action: 'edit', description: 'Can edit projects' },
  { resource: 'projects', action: 'delete', description: 'Can delete projects' },
  { resource: 'gallery', action: 'view', description: 'Can view gallery' },
  { resource: 'gallery', action: 'create', description: 'Can add gallery items' },
  { resource: 'gallery', action: 'edit', description: 'Can edit gallery items' },
  { resource: 'gallery', action: 'delete', description: 'Can delete gallery items' },
  { resource: 'blog', action: 'view', description: 'Can view blog posts' },
  { resource: 'blog', action: 'create', description: 'Can create blog posts' },
  { resource: 'blog', action: 'edit', description: 'Can edit blog posts' },
  { resource: 'blog', action: 'delete', description: 'Can delete blog posts' },
  { resource: 'enrollments', action: 'view', description: 'Can view enrollments' },
  { resource: 'enrollments', action: 'manage', description: 'Can manage enrollments' },
  { resource: 'users', action: 'view', description: 'Can view users' },
  { resource: 'users', action: 'create', description: 'Can create users' },
  { resource: 'users', action: 'edit', description: 'Can edit users' },
  { resource: 'users', action: 'delete', description: 'Can delete users' },
  { resource: 'roles', action: 'view', description: 'Can view roles' },
  { resource: 'roles', action: 'manage', description: 'Can manage roles and permissions' },
  { resource: 'analytics', action: 'view', description: 'Can view analytics' },
  { resource: 'schedule', action: 'view', description: 'Can view schedule' },
  { resource: 'schedule', action: 'manage', description: 'Can manage schedule' },
  { resource: 'notifications', action: 'view', description: 'Can view notifications' },
  { resource: 'notifications', action: 'send', description: 'Can send notifications' },
  { resource: 'api_keys', action: 'view', description: 'Can view API keys' },
  { resource: 'api_keys', action: 'manage', description: 'Can manage API keys' },
];

// System roles that should exist
const SYSTEM_ROLES = [
  { name: 'admin', description: 'Full access to all features', is_system_role: true },
  { name: 'editor', description: 'Can manage content but not users or roles', is_system_role: true },
  { name: 'content_creator', description: 'Can create and manage blog, gallery, projects', is_system_role: true },
  { name: 'coordinator', description: 'Can manage events, enrollments, and schedules', is_system_role: true },
  { name: 'user', description: 'Basic user access (no CMS access)', is_system_role: true },
];

const RolesManager = () => {
  const [roles, setRoles] = useState<Role[]>([]);
  const [permissions, setPermissions] = useState<Permission[]>([]);
  const [selectedRole, setSelectedRole] = useState<Role | null>(null);
  const [rolePermissions, setRolePermissions] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [formData, setFormData] = useState({ name: "", description: "" });
  const [seeding, setSeeding] = useState(false);
  const { toast } = useToast();

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [rolesRes, permissionsRes] = await Promise.all([
        supabase.from("roles").select("*").order("is_system_role", { ascending: false }).order("name"),
        supabase.from("permissions").select("*").order("resource, action")
      ]);

      if (rolesRes.error) throw rolesRes.error;
      if (permissionsRes.error) throw permissionsRes.error;

      setRoles(rolesRes.data || []);
      setPermissions(permissionsRes.data || []);
    } catch (error) {
      const err = error as Error;
      toast({ title: "Error", description: err.message, variant: "destructive" });
    } finally {
      setLoading(false);
    }
  };

  const seedSystemData = async () => {
    setSeeding(true);
    try {
      // Seed system roles
      for (const role of SYSTEM_ROLES) {
        const { error } = await supabase
          .from("roles")
          .upsert(role, { onConflict: 'name' });

        if (error && !error.message.includes('duplicate')) {
          console.error('Error seeding role:', error);
        }
      }

      // Seed permissions
      for (const perm of CMS_PERMISSIONS) {
        const { error } = await supabase
          .from("permissions")
          .upsert(perm, { onConflict: 'resource,action' });

        if (error && !error.message.includes('duplicate')) {
          console.error('Error seeding permission:', error);
        }
      }

      toast({ title: "Success", description: "System roles and permissions have been initialized" });
      await fetchData();
    } catch (error) {
      const err = error as Error;
      toast({ title: "Error", description: err.message, variant: "destructive" });
    } finally {
      setSeeding(false);
    }
  };

  const fetchRolePermissions = async (roleId: string) => {
    try {
      const { data, error } = await supabase
        .from("role_permissions")
        .select("permission_id")
        .eq("role_id", roleId);

      if (error) throw error;
      setRolePermissions(data.map(rp => rp.permission_id));
    } catch (error) {
      const err = error as Error;
      toast({ title: "Error", description: err.message, variant: "destructive" });
    }
  };

  const handleEditRole = async (role: Role) => {
    setSelectedRole(role);
    setFormData({ name: role.name, description: role.description || "" });
    await fetchRolePermissions(role.id);
    setDialogOpen(true);
  };

  const handleCreateRole = async () => {
    if (!formData.name.trim()) {
      toast({ title: "Error", description: "Role name is required", variant: "destructive" });
      return;
    }

    try {
      const { error } = await supabase.from("roles").insert({
        name: formData.name,
        description: formData.description,
        is_system_role: false
      });

      if (error) throw error;

      toast({ title: "Success", description: "Role created successfully" });
      fetchData();
      setDialogOpen(false);
      setFormData({ name: "", description: "" });
    } catch (error) {
      const err = error as Error;
      toast({ title: "Error", description: err.message, variant: "destructive" });
    }
  };

  const handleUpdatePermissions = async () => {
    if (!selectedRole) return;

    try {
      // Delete existing permissions
      await supabase.from("role_permissions").delete().eq("role_id", selectedRole.id);

      // Insert new permissions
      if (rolePermissions.length > 0) {
        const { error } = await supabase.from("role_permissions").insert(
          rolePermissions.map(permId => ({
            role_id: selectedRole.id,
            permission_id: permId
          }))
        );

        if (error) throw error;
      }

      toast({ title: "Success", description: "Permissions updated successfully" });
      setDialogOpen(false);
      setSelectedRole(null);
    } catch (error) {
      const err = error as Error;
      toast({ title: "Error", description: err.message, variant: "destructive" });
    }
  };

  const handleDeleteRole = async (id: string, isSystem: boolean) => {
    if (isSystem) {
      toast({ title: "Error", description: "Cannot delete system roles", variant: "destructive" });
      return;
    }

    if (!confirm("Are you sure you want to delete this role?")) return;

    try {
      const { error } = await supabase.from("roles").delete().eq("id", id);
      if (error) throw error;

      toast({ title: "Success", description: "Role deleted successfully" });
      fetchData();
    } catch (error) {
      const err = error as Error;
      toast({ title: "Error", description: err.message, variant: "destructive" });
    }
  };

  const togglePermission = (permId: string) => {
    setRolePermissions(prev =>
      prev.includes(permId) ? prev.filter(id => id !== permId) : [...prev, permId]
    );
  };

  const groupedPermissions = permissions.reduce((acc, perm) => {
    if (!acc[perm.resource]) acc[perm.resource] = [];
    acc[perm.resource].push(perm);
    return acc;
  }, {} as Record<string, Permission[]>);

  if (loading) return <Loading size="lg" className="h-64" />;

  return (
    <div className="p-8 space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold flex items-center gap-2">
            <Shield className="h-8 w-8" />
            Roles & Permissions
          </h1>
          <p className="text-muted-foreground mt-1">
            Manage user roles and their CMS access permissions
          </p>
        </div>
        <div className="flex gap-2">
          <Button
            variant="outline"
            onClick={seedSystemData}
            disabled={seeding}
          >
            {seeding ? (
              <>
                <RefreshCw className="h-4 w-4 mr-2 animate-spin" />
                Initializing...
              </>
            ) : (
              <>
                <Database className="h-4 w-4 mr-2" />
                Initialize Roles
              </>
            )}
          </Button>
          <Dialog open={dialogOpen && !selectedRole} onOpenChange={setDialogOpen}>
            <DialogTrigger asChild>
              <Button onClick={() => { setFormData({ name: "", description: "" }); setSelectedRole(null); }}>
                <Plus className="h-4 w-4 mr-2" />
                Create Role
              </Button>
            </DialogTrigger>
            <DialogContent>
              <DialogHeader>
                <DialogTitle>Create New Role</DialogTitle>
                <DialogDescription>
                  Define a new role and its basic properties.
                </DialogDescription>
              </DialogHeader>
              <div className="space-y-4">
                <div className="space-y-2">
                  <label className="text-sm font-medium">Role Name</label>
                  <Input
                    placeholder="e.g., moderator"
                    value={formData.name}
                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-medium">Description</label>
                  <Textarea
                    placeholder="Describe what this role can do..."
                    value={formData.description}
                    onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  />
                </div>
                <Button onClick={handleCreateRole} className="w-full">Create Role</Button>
              </div>
            </DialogContent>
          </Dialog>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">Total Roles</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{roles.length}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">System Roles</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-primary">
              {roles.filter(r => r.is_system_role).length}
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">Permissions</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{permissions.length}</div>
          </CardContent>
        </Card>
      </div>

      {roles.length === 0 && (
        <Alert>
          <AlertCircle className="h-4 w-4" />
          <AlertDescription>
            No roles found. Click "Initialize Roles" to create system roles and permissions.
          </AlertDescription>
        </Alert>
      )}

      <Card>
        <CardHeader>
          <CardTitle>CMS Access Roles</CardTitle>
          <CardDescription>
            Configure which permissions each role has. Click "Edit" to customize CMS access for each role.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Role Name</TableHead>
                <TableHead>Description</TableHead>
                <TableHead>Type</TableHead>
                <TableHead>CMS Access</TableHead>
                <TableHead className="text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {roles.map((role) => {
                const hasCMSAccess = ['admin', 'editor', 'content_creator', 'coordinator'].includes(role.name);
                return (
                  <TableRow key={role.id}>
                    <TableCell className="font-medium capitalize">{role.name.replace('_', ' ')}</TableCell>
                    <TableCell className="text-muted-foreground">{role.description}</TableCell>
                    <TableCell>
                      <Badge variant={role.is_system_role ? "default" : "secondary"}>
                        {role.is_system_role ? "System" : "Custom"}
                      </Badge>
                    </TableCell>
                    <TableCell>
                      <Badge variant={hasCMSAccess ? "outline" : "secondary"} className={hasCMSAccess ? "border-green-500 text-green-500" : ""}>
                        {hasCMSAccess ? "Yes" : "No"}
                      </Badge>
                    </TableCell>
                    <TableCell className="text-right">
                      <div className="flex justify-end gap-2">
                        <Button variant="outline" size="sm" onClick={() => handleEditRole(role)}>
                          <Edit className="h-4 w-4 mr-1" />
                          Permissions
                        </Button>
                        {!role.is_system_role && (
                          <Button
                            variant="destructive"
                            size="sm"
                            onClick={() => handleDeleteRole(role.id, role.is_system_role)}
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        )}
                      </div>
                    </TableCell>
                  </TableRow>
                );
              })}
            </TableBody>
          </Table>
        </CardContent>
      </Card>

      <Dialog open={dialogOpen && !!selectedRole} onOpenChange={setDialogOpen}>
        <DialogContent className="max-w-3xl max-h-[80vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Edit Permissions: {selectedRole?.name}</DialogTitle>
            <DialogDescription>
              Manage access rights for this role across the system.
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-6">
            {Object.entries(groupedPermissions).map(([resource, perms]) => (
              <Card key={resource}>
                <CardHeader>
                  <CardTitle className="text-lg capitalize">{resource}</CardTitle>
                </CardHeader>
                <CardContent className="space-y-2">
                  {perms.map(perm => (
                    <div key={perm.id} className="flex items-center space-x-2">
                      <Checkbox
                        checked={rolePermissions.includes(perm.id)}
                        onCheckedChange={() => togglePermission(perm.id)}
                      />
                      <label className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70">
                        {perm.action} - {perm.description}
                      </label>
                    </div>
                  ))}
                </CardContent>
              </Card>
            ))}
            <Button onClick={handleUpdatePermissions} className="w-full">Save Permissions</Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default RolesManager;

import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { useToast } from "@/hooks/use-toast";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  DialogDescription,
} from "@/components/ui/dialog";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Plus, Pencil, Trash2 } from "lucide-react";
import { Switch } from "@/components/ui/switch";
import { z } from "zod";

const scheduleSchema = z.object({
  title: z.string().trim().min(1, "Title is required").max(200, "Title must be less than 200 characters"),
  description: z.string().max(1000, "Description must be less than 1000 characters").transform(val => val || "").optional(),
  day_of_week: z.string().min(1, "Day of week is required"),
  start_time: z.string().regex(/^\d{2}:\d{2}$/, "Invalid time format (use HH:MM)").transform(val => val || "").optional().or(z.literal("")),
  end_time: z.string().regex(/^\d{2}:\d{2}$/, "Invalid time format (use HH:MM)").transform(val => val || "").optional().or(z.literal("")),
  location: z.string().max(200, "Location must be less than 200 characters").transform(val => val || "").optional(),
  is_active: z.boolean(),
});

interface Schedule {
  id: string;
  title: string;
  description: string;
  day_of_week: string;
  start_time: string;
  end_time: string;
  location: string;
  is_active: boolean;
}

const ScheduleManager = () => {
  const { toast } = useToast();
  const [schedules, setSchedules] = useState<Schedule[]>([]);
  const [loading, setLoading] = useState(true);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingSchedule, setEditingSchedule] = useState<Schedule | null>(null);
  const [formData, setFormData] = useState({
    title: "",
    description: "",
    day_of_week: "",
    start_time: "",
    end_time: "",
    location: "",
    is_active: true,
  });

  const daysOfWeek = [
    "Monday",
    "Tuesday",
    "Wednesday",
    "Thursday",
    "Friday",
    "Saturday",
    "Sunday",
  ];

  useEffect(() => {
    fetchSchedules();
  }, []);

  const fetchSchedules = async () => {
    try {
      const { data, error } = await supabase
        .from("schedule")
        .select("*")
        .order("day_of_week", { ascending: true });

      if (error) throw error;
      setSchedules(data || []);
    } catch (error) {
      const err = error as Error;
      toast({
        title: "Error",
        description: err.message,
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    try {
      // Validate input data
      const validationResult = scheduleSchema.safeParse(formData);
      if (!validationResult.success) {
        const errors = validationResult.error.errors.map(err => err.message).join(", ");
        toast({
          title: "Validation Error",
          description: errors,
          variant: "destructive",
        });
        return;
      }

      const dataToSave = validationResult.data as any;

      if (editingSchedule) {
        const { error } = await supabase
          .from("schedule")
          .update(dataToSave)
          .eq("id", editingSchedule.id);

        if (error) throw error;
        toast({ title: "Schedule updated successfully!" });
      } else {
        const { error } = await supabase
          .from("schedule")
          .insert([dataToSave]);

        if (error) throw error;
        toast({ title: "Schedule created successfully!" });
      }

      setDialogOpen(false);
      resetForm();
      fetchSchedules();
    } catch (error) {
      const err = error as Error;
      toast({
        title: "Error",
        description: err.message || "Failed to save schedule. Please try again.",
        variant: "destructive",
      });
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to delete this schedule?")) return;

    try {
      const { error } = await supabase
        .from("schedule")
        .delete()
        .eq("id", id);

      if (error) throw error;
      toast({ title: "Schedule deleted successfully!" });
      fetchSchedules();
    } catch (error) {
      const err = error as Error;
      toast({
        title: "Error",
        description: err.message,
        variant: "destructive",
      });
    }
  };

  const handleEdit = (schedule: Schedule) => {
    setEditingSchedule(schedule);
    setFormData({
      title: schedule.title,
      description: schedule.description || "",
      day_of_week: schedule.day_of_week || "",
      start_time: schedule.start_time || "",
      end_time: schedule.end_time || "",
      location: schedule.location || "",
      is_active: schedule.is_active,
    });
    setDialogOpen(true);
  };

  const resetForm = () => {
    setFormData({
      title: "",
      description: "",
      day_of_week: "",
      start_time: "",
      end_time: "",
      location: "",
      is_active: true,
    });
    setEditingSchedule(null);
  };

  return (
    <div>
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-4xl font-bold gradient-text mb-2">Schedule Manager</h1>
          <p className="text-muted-foreground">Manage club meeting schedules</p>
        </div>
        <Dialog open={dialogOpen} onOpenChange={(open) => {
          setDialogOpen(open);
          if (!open) resetForm();
        }}>
          <DialogTrigger asChild>
            <Button variant="hero" size="lg">
              <Plus className="w-5 h-5" />
              Add Schedule
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-2xl">
            <DialogHeader>
              <DialogTitle>{editingSchedule ? "Edit Schedule" : "Create New Schedule"}</DialogTitle>
              <DialogDescription>
                Set up the schedule details below.
              </DialogDescription>
            </DialogHeader>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-medium mb-2">Title</label>
                <Input
                  value={formData.title}
                  onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                  required
                  placeholder="Innovation Workshop"
                />
              </div>

              <div>
                <label className="block text-sm font-medium mb-2">Description</label>
                <Textarea
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  placeholder="Activity description..."
                  rows={3}
                />
              </div>

              <div className="grid grid-cols-3 gap-4">
                <div>
                  <label className="block text-sm font-medium mb-2">Day</label>
                  <Select
                    value={formData.day_of_week}
                    onValueChange={(value) => setFormData({ ...formData, day_of_week: value })}
                  >
                    <SelectTrigger>
                      <SelectValue placeholder="Select day" />
                    </SelectTrigger>
                    <SelectContent>
                      {daysOfWeek.map((day) => (
                        <SelectItem key={day} value={day}>
                          {day}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <label className="block text-sm font-medium mb-2">Start Time</label>
                  <Input
                    type="time"
                    value={formData.start_time}
                    onChange={(e) => setFormData({ ...formData, start_time: e.target.value })}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium mb-2">End Time</label>
                  <Input
                    type="time"
                    value={formData.end_time}
                    onChange={(e) => setFormData({ ...formData, end_time: e.target.value })}
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium mb-2">Location</label>
                <Input
                  value={formData.location}
                  onChange={(e) => setFormData({ ...formData, location: e.target.value })}
                  placeholder="Innovation Lab"
                />
              </div>

              <div className="flex items-center gap-2">
                <Switch
                  checked={formData.is_active}
                  onCheckedChange={(checked) => setFormData({ ...formData, is_active: checked })}
                />
                <label className="text-sm font-medium">Active Schedule</label>
              </div>

              <div className="flex gap-3 pt-4">
                <Button type="submit" variant="hero" className="flex-1">
                  {editingSchedule ? "Update Schedule" : "Create Schedule"}
                </Button>
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => setDialogOpen(false)}
                >
                  Cancel
                </Button>
              </div>
            </form>
          </DialogContent>
        </Dialog>
      </div>

      <div className="glass-card rounded-xl overflow-hidden">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Title</TableHead>
              <TableHead>Day</TableHead>
              <TableHead>Time</TableHead>
              <TableHead>Location</TableHead>
              <TableHead>Status</TableHead>
              <TableHead>Actions</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {schedules.map((schedule) => (
              <TableRow key={schedule.id}>
                <TableCell className="font-medium">{schedule.title}</TableCell>
                <TableCell>{schedule.day_of_week || "-"}</TableCell>
                <TableCell>
                  {schedule.start_time && schedule.end_time
                    ? `${schedule.start_time} - ${schedule.end_time}`
                    : "-"}
                </TableCell>
                <TableCell>{schedule.location || "-"}</TableCell>
                <TableCell>
                  {schedule.is_active ? (
                    <span className="px-2 py-1 bg-secondary text-secondary-foreground rounded-full text-xs">
                      Active
                    </span>
                  ) : (
                    <span className="px-2 py-1 bg-muted text-muted-foreground rounded-full text-xs">
                      Inactive
                    </span>
                  )}
                </TableCell>
                <TableCell>
                  <div className="flex gap-2">
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => handleEdit(schedule)}
                    >
                      <Pencil className="w-4 h-4" />
                    </Button>
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => handleDelete(schedule.id)}
                    >
                      <Trash2 className="w-4 h-4 text-destructive" />
                    </Button>
                  </div>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>
    </div>
  );
};

export default ScheduleManager;

import { useState, useEffect } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { useToast } from "@/hooks/use-toast";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  DialogDescription,
} from "@/components/ui/dialog";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Plus, Pencil, Trash2 } from "lucide-react";
import { z } from "zod";

const teamMemberSchema = z.object({
  name: z.string().trim().min(1, "Name is required").max(100, "Name must be less than 100 characters"),
  role: z.string().trim().min(1, "Role is required").max(100, "Role must be less than 100 characters"),
  description: z.string().max(500, "Description must be less than 500 characters").transform(val => val || "").optional(),
  image_url: z.string().url("Invalid URL format").max(500, "URL too long").transform(val => val || "").optional().or(z.literal("")),
  email: z.string().email("Invalid email format").max(255, "Email too long").transform(val => val || "").optional().or(z.literal("")),
  linkedin_url: z.string().url("Invalid LinkedIn URL").max(500, "URL too long").transform(val => val || "").optional().or(z.literal("")),
  display_order: z.number().int().min(0, "Display order must be positive"),
});

interface TeamMember {
  id: string;
  name: string;
  role: string;
  description: string;
  image_url: string;
  email: string;
  linkedin_url: string;
  display_order: number;
}

const TeamManager = () => {
  const { toast } = useToast();
  const [members, setMembers] = useState<TeamMember[]>([]);
  const [loading, setLoading] = useState(true);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingMember, setEditingMember] = useState<TeamMember | null>(null);
  const [formData, setFormData] = useState({
    name: "",
    role: "",
    description: "",
    image_url: "",
    email: "",
    linkedin_url: "",
    display_order: 0,
  });

  useEffect(() => {
    fetchMembers();
  }, []);

  const fetchMembers = async () => {
    try {
      const { data, error } = await supabase
        .from("team_members")
        .select("*")
        .order("display_order", { ascending: true });

      if (error) throw error;
      setMembers(data || []);
    } catch (error) {
      const err = error as Error;
      toast({
        title: "Error",
        description: err.message,
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    try {
      // Validate input data
      const validationResult = teamMemberSchema.safeParse(formData);
      if (!validationResult.success) {
        const errors = validationResult.error.errors.map(err => err.message).join(", ");
        toast({
          title: "Validation Error",
          description: errors,
          variant: "destructive",
        });
        return;
      }

      const dataToSave = validationResult.data as any;

      if (editingMember) {
        const { error } = await supabase
          .from("team_members")
          .update(dataToSave)
          .eq("id", editingMember.id);

        if (error) throw error;
        toast({ title: "Team member updated successfully!" });
      } else {
        const { error } = await supabase
          .from("team_members")
          .insert([dataToSave]);

        if (error) throw error;
        toast({ title: "Team member added successfully!" });
      }

      setDialogOpen(false);
      resetForm();
      fetchMembers();
    } catch (error) {
      const err = error as Error;
      toast({
        title: "Error",
        description: err.message || "Failed to save team member. Please try again.",
        variant: "destructive",
      });
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to delete this team member?")) return;

    try {
      const { error } = await supabase
        .from("team_members")
        .delete()
        .eq("id", id);

      if (error) throw error;
      toast({ title: "Team member deleted successfully!" });
      fetchMembers();
    } catch (error) {
      const err = error as Error;
      toast({
        title: "Error",
        description: err.message,
        variant: "destructive",
      });
    }
  };

  const handleEdit = (member: TeamMember) => {
    setEditingMember(member);
    setFormData({
      name: member.name,
      role: member.role,
      description: member.description || "",
      image_url: member.image_url || "",
      email: member.email || "",
      linkedin_url: member.linkedin_url || "",
      display_order: member.display_order,
    });
    setDialogOpen(true);
  };

  const resetForm = () => {
    setFormData({
      name: "",
      role: "",
      description: "",
      image_url: "",
      email: "",
      linkedin_url: "",
      display_order: 0,
    });
    setEditingMember(null);
  };

  return (
    <div>
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-4xl font-bold gradient-text mb-2">Team Manager</h1>
          <p className="text-muted-foreground">Manage club leadership and members</p>
        </div>
        <Dialog open={dialogOpen} onOpenChange={(open) => {
          setDialogOpen(open);
          if (!open) resetForm();
        }}>
          <DialogTrigger asChild>
            <Button variant="hero" size="lg">
              <Plus className="w-5 h-5" />
              Add Member
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-2xl">
            <DialogHeader>
              <DialogTitle>{editingMember ? "Edit Team Member" : "Add Team Member"}</DialogTitle>
              <DialogDescription>
                Enter the details of the team member below.
              </DialogDescription>
            </DialogHeader>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium mb-2">Name</label>
                  <Input
                    value={formData.name}
                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                    required
                    placeholder="John Doe"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium mb-2">Role</label>
                  <Input
                    value={formData.role}
                    onChange={(e) => setFormData({ ...formData, role: e.target.value })}
                    required
                    placeholder="Chief Innovator"
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium mb-2">Description</label>
                <Textarea
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  placeholder="Brief description of responsibilities..."
                  rows={3}
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium mb-2">Email</label>
                  <Input
                    type="email"
                    value={formData.email}
                    onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                    placeholder="email@example.com"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium mb-2">LinkedIn URL</label>
                  <Input
                    value={formData.linkedin_url}
                    onChange={(e) => setFormData({ ...formData, linkedin_url: e.target.value })}
                    placeholder="https://linkedin.com/in/..."
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium mb-2">Image URL</label>
                  <Input
                    value={formData.image_url}
                    onChange={(e) => setFormData({ ...formData, image_url: e.target.value })}
                    placeholder="https://..."
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium mb-2">Display Order</label>
                  <Input
                    type="number"
                    value={formData.display_order}
                    onChange={(e) => setFormData({ ...formData, display_order: parseInt(e.target.value) })}
                  />
                </div>
              </div>

              <div className="flex gap-3 pt-4">
                <Button type="submit" variant="hero" className="flex-1">
                  {editingMember ? "Update Member" : "Add Member"}
                </Button>
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => setDialogOpen(false)}
                >
                  Cancel
                </Button>
              </div>
            </form>
          </DialogContent>
        </Dialog>
      </div>

      <div className="glass-card rounded-xl overflow-hidden">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Name</TableHead>
              <TableHead>Role</TableHead>
              <TableHead>Email</TableHead>
              <TableHead>Order</TableHead>
              <TableHead>Actions</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {members.map((member) => (
              <TableRow key={member.id}>
                <TableCell className="font-medium">{member.name}</TableCell>
                <TableCell>{member.role}</TableCell>
                <TableCell>{member.email || "-"}</TableCell>
                <TableCell>{member.display_order}</TableCell>
                <TableCell>
                  <div className="flex gap-2">
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => handleEdit(member)}
                    >
                      <Pencil className="w-4 h-4" />
                    </Button>
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => handleDelete(member.id)}
                    >
                      <Trash2 className="w-4 h-4 text-destructive" />
                    </Button>
                  </div>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>
    </div>
  );
};

export default TeamManager;

import { useState, useEffect, useRef } from "react";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter, DialogDescription } from "@/components/ui/dialog";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Trash2, UserPlus, Users, Edit, RefreshCw, Search, AlertCircle, Key, Upload, Circle } from "lucide-react";
import { Loading } from "@/components/ui/loading";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { AppRole } from "@/contexts/RoleContext";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";

interface UserWithRole {
  id: string;
  email: string;
  full_name: string | null;
  avatar_url: string | null;
  created_at: string;
  role: AppRole | null;
  role_id: string | null;
  is_active?: boolean;
  last_activity?: string;
}

interface Role {
  id: string;
  name: string;
  description: string | null;
}

interface ActiveSession {
  user_id: string;
  last_activity_at: string;
  is_active: boolean;
}

const ROLE_OPTIONS: { value: AppRole; label: string; description: string }[] = [
  { value: 'admin', label: 'Admin', description: 'Full access to all features' },
  { value: 'editor', label: 'Editor', description: 'Can manage content but not users or roles' },
  { value: 'content_creator', label: 'Content Creator', description: 'Can create and manage blog content' },
  { value: 'coordinator', label: 'Coordinator', description: 'Can manage events and enrollments' },
  { value: 'user', label: 'User', description: 'Regular user access' },
];

const UsersManager = () => {
  const [users, setUsers] = useState<UserWithRole[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [activeSessions, setActiveSessions] = useState<ActiveSession[]>([]);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState<string | null>(null);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editDialogOpen, setEditDialogOpen] = useState(false);
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [selectedUser, setSelectedUser] = useState<UserWithRole | null>(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [activeTab, setActiveTab] = useState("all");
  const [formData, setFormData] = useState({
    email: "",
    password: "",
    fullName: "",
    role: "user" as AppRole
  });
  const [editFormData, setEditFormData] = useState({
    fullName: "",
    role: "user" as AppRole,
    newPassword: "",
    avatarUrl: ""
  });
  const [avatarFile, setAvatarFile] = useState<File | null>(null);
  const [avatarPreview, setAvatarPreview] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { toast } = useToast();

  useEffect(() => {
    fetchData();

    // Set up Realtime subscription for user status updates
    const channel = supabase
      .channel('schema-db-changes')
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'user_sessions'
        },
        (payload) => {
          console.log('Realtime update:', payload);

          if (payload.eventType === 'INSERT' || payload.eventType === 'UPDATE') {
            const newSession = payload.new as ActiveSession;
            // Update the specific user's status in the list
            setUsers(currentUsers =>
              currentUsers.map(user => {
                if (user.id === newSession.user_id) {
                  return {
                    ...user,
                    is_active: newSession.is_active,
                    last_activity: newSession.last_activity_at
                  };
                }
                return user;
              })
            );
          } else if (payload.eventType === 'DELETE') {
            const oldSession = payload.old as { id: string, user_id: string }; // Supabase sends old record with ID
            // Ideally we'd match by user_id, but DELETE payload might strictly contain PK.
            // Check Supabase config for REPLICA IDENTITY. Usually PK is sent.
            // user_sessions PK is likely id, but it has user_id FK. 
            // If we can't reliably get user_id from OLD on DELETE without full replica identity,
            // we might need to rely on the fact that we can infer it or just refresh.
            // However, assuming standard setup, we can try to refresh or if we track session IDs.
            // Let's assume we might need to match by scanning if user_id is missing.

            // safer approach for DELETE if we aren't sure of payload content:
            // inspect payload. If user_id is present, use it.
            // If not, we might need to refresh or just set offline if we have the session ID mapped.
            // BUT: UsersWithRole doesn't store session ID. 
            // So let's re-fetch data on DELETE to be safe and accurate, 
            // OR checks if payload.old has user_id.

            if (payload.old && (payload.old as any).user_id) {
              const userId = (payload.old as any).user_id;
              setUsers(currentUsers =>
                currentUsers.map(user => {
                  if (user.id === userId) {
                    return { ...user, is_active: false };
                  }
                  return user;
                })
              );
            } else {
              // Fallback: if we don't have user_id in delete payload, refreshing is safest
              // identifying which user went offline is hard without it.
              // But usually user_sessions DELETE means "logged out".
              // Let's trigger a background refresh for accuracy.
              fetchData();
            }
          }
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, []);

  const fetchData = async () => {
    try {
      // Don't set loading true on background refreshes if we have data
      // avoiding full screen spinner flicker
      if (users.length === 0) setLoading(true);

      const { data: { session } } = await supabase.auth.getSession();

      if (!session) {
        toast({
          title: "Authentication required",
          description: "Please log in to view users",
          variant: "destructive"
        });
        setLoading(false);
        return;
      }

      // Fetch all profiles with avatar_url
      const { data: profilesData, error: profilesError } = await supabase
        .from("profiles")
        .select("id, email, full_name, avatar_url, created_at")
        .order("created_at", { ascending: false });

      if (profilesError) {
        console.error("Error fetching profiles:", profilesError);
        throw profilesError;
      }

      // Fetch all user roles
      const { data: userRolesData, error: userRolesError } = await supabase
        .from("user_roles")
        .select("id, user_id, role");

      if (userRolesError) {
        console.error("Error fetching user roles:", userRolesError);
        throw userRolesError;
      }

      // Fetch active sessions (last 30 minutes)
      const thirtyMinutesAgo = new Date(Date.now() - 30 * 60 * 1000).toISOString();
      const { data: sessionsData, error: sessionsError } = await supabase
        .from("user_sessions")
        .select("user_id, last_activity_at, is_active")
        .eq("is_active", true)
        .gte("last_activity_at", thirtyMinutesAgo);

      if (!sessionsError && sessionsData) {
        setActiveSessions(sessionsData);
      }

      // Fetch available roles from roles table
      const { data: rolesData, error: rolesError } = await supabase
        .from("roles")
        .select("id, name, description")
        .order("name");

      if (rolesError) {
        console.error("Error fetching roles:", rolesError);
      }

      // Map roles and active status to users
      const usersWithRoles: UserWithRole[] = (profilesData || []).map(profile => {
        const userRole = userRolesData?.find(ur => ur.user_id === profile.id);
        const userSession = sessionsData?.find(s => s.user_id === profile.id);
        return {
          id: profile.id,
          email: profile.email,
          full_name: profile.full_name,
          avatar_url: profile.avatar_url,
          created_at: profile.created_at,
          role: userRole?.role || null,
          role_id: userRole?.id || null,
          is_active: userSession?.is_active || false,
          last_activity: userSession?.last_activity_at || undefined
        };
      });

      setUsers(usersWithRoles);
      setRoles(rolesData || []);
    } catch (error) {
      const err = error as Error;
      console.error("Error fetching users:", err);
      toast({
        title: "Error loading users",
        description: err.message,
        variant: "destructive"
      });
    } finally {
      setLoading(false);
    }
  };

  const handleCreateUser = async () => {
    if (!formData.email || !formData.password) {
      toast({
        title: "Validation Error",
        description: "Email and password are required",
        variant: "destructive"
      });
      return;
    }

    if (formData.password.length < 6) {
      toast({
        title: "Validation Error",
        description: "Password must be at least 6 characters",
        variant: "destructive"
      });
      return;
    }

    setActionLoading("create");
    try {
      const { data: { session } } = await supabase.auth.getSession();

      if (!session) {
        toast({
          title: "Error",
          description: "You must be logged in to create users",
          variant: "destructive"
        });
        return;
      }

      const response = await fetch(
        `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/admin-create-user`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${session.access_token}`,
          },
          body: JSON.stringify({
            email: formData.email,
            password: formData.password,
            fullName: formData.fullName,
            role: formData.role,
          }),
        }
      );

      const result = await response.json();

      if (!response.ok) {
        throw new Error(result.error || 'Failed to create user');
      }

      toast({
        title: "User Created",
        description: `${formData.email} has been added successfully as ${formData.role}`
      });

      await fetchData();
      setDialogOpen(false);
      setFormData({ email: "", password: "", fullName: "", role: "user" });
    } catch (error) {
      const err = error as Error;
      console.error("Error creating user:", err);
      toast({
        title: "Error creating user",
        description: err.message,
        variant: "destructive"
      });
    } finally {
      setActionLoading(null);
    }
  };

  const handleUpdateUser = async () => {
    if (!selectedUser) return;

    setActionLoading("update");
    try {
      const { data: { session } } = await supabase.auth.getSession();

      if (!session) {
        toast({
          title: "Error",
          description: "You must be logged in to update users",
          variant: "destructive"
        });
        return;
      }

      // Upload avatar if selected
      let avatarUrl = editFormData.avatarUrl;
      if (avatarFile) {
        const fileExt = avatarFile.name.split('.').pop();
        const fileName = `${selectedUser.id}/${Date.now()}.${fileExt}`;

        const { error: uploadError } = await supabase.storage
          .from('avatars')
          .upload(fileName, avatarFile, { upsert: true });

        if (uploadError) {
          throw new Error('Failed to upload avatar');
        }

        const { data: { publicUrl } } = supabase.storage
          .from('avatars')
          .getPublicUrl(fileName);

        avatarUrl = publicUrl;
      }

      // Call edge function for profile and password updates
      const response = await fetch(
        `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/admin-update-user`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${session.access_token}`,
          },
          body: JSON.stringify({
            userId: selectedUser.id,
            fullName: editFormData.fullName,
            avatarUrl: avatarUrl,
            newPassword: editFormData.newPassword || undefined
          }),
        }
      );

      const result = await response.json();

      if (!response.ok) {
        throw new Error(result.error || 'Failed to update user');
      }

      // Update role separately (handled by client with RLS)
      if (selectedUser.role_id) {
        const { error: roleError } = await supabase
          .from("user_roles")
          .update({ role: editFormData.role })
          .eq("id", selectedUser.role_id);

        if (roleError) throw roleError;
      } else {
        const { error: roleError } = await supabase
          .from("user_roles")
          .insert({
            user_id: selectedUser.id,
            role: editFormData.role
          });

        if (roleError) throw roleError;
      }

      toast({
        title: "User Updated",
        description: `${selectedUser.email} has been updated successfully${editFormData.newPassword ? ' (password changed)' : ''}`
      });

      await fetchData();
      setEditDialogOpen(false);
      setSelectedUser(null);
      setAvatarFile(null);
      setAvatarPreview(null);
    } catch (error) {
      const err = error as Error;
      console.error("Error updating user:", err);
      toast({
        title: "Error updating user",
        description: err.message,
        variant: "destructive"
      });
    } finally {
      setActionLoading(null);
    }
  };

  const handleDeleteUser = async () => {
    if (!selectedUser) return;

    setActionLoading("delete");
    try {
      const { data: { session } } = await supabase.auth.getSession();

      if (!session) {
        toast({
          title: "Error",
          description: "You must be logged in to delete users",
          variant: "destructive"
        });
        return;
      }

      const response = await fetch(
        `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/admin-delete-user`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${session.access_token}`,
          },
          body: JSON.stringify({
            userId: selectedUser.id,
          }),
        }
      );

      const result = await response.json();

      if (!response.ok) {
        throw new Error(result.error || 'Failed to delete user');
      }

      toast({
        title: "User Deleted",
        description: `${selectedUser.email} has been completely removed from the system`
      });

      await fetchData();
      setDeleteDialogOpen(false);
      setSelectedUser(null);
    } catch (error) {
      const err = error as Error;
      console.error("Error deleting user:", err);
      toast({
        title: "Error deleting user",
        description: err.message,
        variant: "destructive"
      });
    } finally {
      setActionLoading(null);
    }
  };

  const openEditDialog = (user: UserWithRole) => {
    setSelectedUser(user);
    setEditFormData({
      fullName: user.full_name || "",
      role: user.role || "user",
      newPassword: "",
      avatarUrl: user.avatar_url || ""
    });
    setAvatarPreview(user.avatar_url || null);
    setAvatarFile(null);
    setEditDialogOpen(true);
  };

  const openDeleteDialog = (user: UserWithRole) => {
    setSelectedUser(user);
    setDeleteDialogOpen(true);
  };

  const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) {
        toast({
          title: "File too large",
          description: "Avatar must be less than 2MB",
          variant: "destructive"
        });
        return;
      }
      setAvatarFile(file);
      setAvatarPreview(URL.createObjectURL(file));
    }
  };

  const filteredUsers = users.filter(user => {
    const matchesSearch = user.email.toLowerCase().includes(searchQuery.toLowerCase()) ||
      (user.full_name?.toLowerCase().includes(searchQuery.toLowerCase()));

    if (activeTab === "active") {
      return matchesSearch && user.is_active;
    }
    return matchesSearch;
  });

  const getRoleBadgeVariant = (role: string | null) => {
    switch (role) {
      case 'admin':
        return 'default';
      case 'user':
        return 'secondary';
      default:
        return 'outline';
    }
  };

  const activeUserCount = users.filter(u => u.is_active).length;

  if (loading) return <Loading size="lg" className="h-64" />;

  return (
    <div className="p-8 space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold flex items-center gap-2">
            <Users className="h-8 w-8" />
            User Management
          </h1>
          <p className="text-muted-foreground mt-1">
            Manage users, roles, passwords, and profile photos
          </p>
        </div>

        <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
          <DialogTrigger asChild>
            <Button className="gap-2">
              <UserPlus className="h-4 w-4" />
              Add User
            </Button>
          </DialogTrigger>
          <DialogContent className="sm:max-w-md">
            <DialogHeader>
              <DialogTitle>Create New User</DialogTitle>
              <DialogDescription>
                Add a new user to the system with specified role
              </DialogDescription>
            </DialogHeader>
            <div className="space-y-4 py-4">
              <div className="space-y-2">
                <label className="text-sm font-medium">Email *</label>
                <Input
                  type="email"
                  placeholder="user@example.com"
                  value={formData.email}
                  onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium">Full Name</label>
                <Input
                  type="text"
                  placeholder="John Doe"
                  value={formData.fullName}
                  onChange={(e) => setFormData({ ...formData, fullName: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium">Password *</label>
                <Input
                  type="password"
                  placeholder="Minimum 6 characters"
                  value={formData.password}
                  onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium">Role *</label>
                <Select
                  value={formData.role}
                  onValueChange={(value: AppRole) => setFormData({ ...formData, role: value })}
                >
                  <SelectTrigger>
                    <SelectValue placeholder="Select Role" />
                  </SelectTrigger>
                  <SelectContent>
                    {ROLE_OPTIONS.map((role) => (
                      <SelectItem key={role.value} value={role.value}>
                        {role.label} - {role.description}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>
            <DialogFooter>
              <Button variant="outline" onClick={() => setDialogOpen(false)}>
                Cancel
              </Button>
              <Button
                onClick={handleCreateUser}
                disabled={actionLoading === "create"}
              >
                {actionLoading === "create" ? (
                  <>
                    <RefreshCw className="h-4 w-4 mr-2 animate-spin" />
                    Creating...
                  </>
                ) : (
                  "Create User"
                )}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">Total Users</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{users.length}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">Active Now</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-green-600 flex items-center gap-2">
              <Circle className="h-3 w-3 fill-green-500" />
              {activeUserCount}
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">Admins</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-primary">
              {users.filter(u => u.role === 'admin').length}
            </div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground">Regular Users</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {users.filter(u => u.role === 'user' || !u.role).length}
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Users Table with Tabs */}
      <Card>
        <CardHeader>
          <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
            <div>
              <CardTitle>Users</CardTitle>
              <CardDescription>View and manage all users in the system</CardDescription>
            </div>
            <div className="flex items-center gap-2 w-full sm:w-auto">
              <div className="relative flex-1 sm:w-64">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Search users..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="pl-9"
                />
              </div>
              <Button variant="outline" size="icon" onClick={fetchData}>
                <RefreshCw className="h-4 w-4" />
              </Button>
            </div>
          </div>
        </CardHeader>
        <CardContent>
          <Tabs value={activeTab} onValueChange={setActiveTab} className="mb-4">
            <TabsList>
              <TabsTrigger value="all">All Users ({users.length})</TabsTrigger>
              <TabsTrigger value="active" className="flex items-center gap-2">
                <Circle className="h-2 w-2 fill-green-500" />
                Active ({activeUserCount})
              </TabsTrigger>
            </TabsList>
          </Tabs>

          {filteredUsers.length === 0 ? (
            <Alert>
              <AlertCircle className="h-4 w-4" />
              <AlertDescription>
                {searchQuery ? "No users found matching your search." :
                  activeTab === "active" ? "No active users at the moment." :
                    "No users found. Add your first user to get started."}
              </AlertDescription>
            </Alert>
          ) : (
            <div className="overflow-x-auto">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>User</TableHead>
                    <TableHead>Role</TableHead>
                    <TableHead>Status</TableHead>
                    <TableHead>Joined</TableHead>
                    <TableHead className="text-right">Actions</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {filteredUsers.map((user) => (
                    <TableRow key={user.id}>
                      <TableCell>
                        <div className="flex items-center gap-3">
                          <Avatar className="h-10 w-10">
                            <AvatarImage src={user.avatar_url || undefined} alt={user.full_name || user.email} />
                            <AvatarFallback>
                              {(user.full_name || user.email).slice(0, 2).toUpperCase()}
                            </AvatarFallback>
                          </Avatar>
                          <div>
                            <p className="font-medium">{user.full_name || <span className="text-muted-foreground">Not set</span>}</p>
                            <p className="text-sm text-muted-foreground">{user.email}</p>
                          </div>
                        </div>
                      </TableCell>
                      <TableCell>
                        <Badge variant={getRoleBadgeVariant(user.role)}>
                          {user.role || "No Role"}
                        </Badge>
                      </TableCell>
                      <TableCell>
                        <div className="flex items-center gap-2">
                          <Circle className={`h-2 w-2 ${user.is_active ? 'fill-green-500 text-green-500' : 'fill-gray-300 text-gray-300'}`} />
                          <span className="text-sm">{user.is_active ? 'Online' : 'Offline'}</span>
                        </div>
                      </TableCell>
                      <TableCell>{new Date(user.created_at).toLocaleDateString()}</TableCell>
                      <TableCell className="text-right">
                        <div className="flex justify-end gap-2">
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => openEditDialog(user)}
                            title="Edit user"
                          >
                            <Edit className="h-4 w-4" />
                          </Button>
                          <Button
                            variant="destructive"
                            size="sm"
                            onClick={() => openDeleteDialog(user)}
                            title="Delete user"
                          >
                            <Trash2 className="h-4 w-4" />
                          </Button>
                        </div>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Edit Dialog with Enhanced Features */}
      <Dialog open={editDialogOpen} onOpenChange={setEditDialogOpen}>
        <DialogContent className="sm:max-w-lg">
          <DialogHeader>
            <DialogTitle>Edit User</DialogTitle>
            <DialogDescription>
              Update user information for {selectedUser?.email}
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-6 py-4">
            {/* Avatar Upload */}
            <div className="flex items-center gap-4">
              <Avatar className="h-20 w-20">
                <AvatarImage src={avatarPreview || undefined} />
                <AvatarFallback>
                  {(selectedUser?.full_name || selectedUser?.email || "U").slice(0, 2).toUpperCase()}
                </AvatarFallback>
              </Avatar>
              <div className="space-y-2">
                <input
                  type="file"
                  ref={fileInputRef}
                  accept="image/*"
                  onChange={handleAvatarChange}
                  className="hidden"
                />
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => fileInputRef.current?.click()}
                >
                  <Upload className="h-4 w-4 mr-2" />
                  Upload Photo
                </Button>
                <p className="text-xs text-muted-foreground">Max 2MB, JPG/PNG/GIF</p>
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-sm font-medium">Email</label>
              <Input
                type="email"
                value={selectedUser?.email || ""}
                disabled
                className="bg-muted"
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium">Full Name</label>
              <Input
                type="text"
                placeholder="John Doe"
                value={editFormData.fullName}
                onChange={(e) => setEditFormData({ ...editFormData, fullName: e.target.value })}
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-medium">Role</label>
              <Select
                value={editFormData.role}
                onValueChange={(value: AppRole) => setEditFormData({ ...editFormData, role: value })}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Select Role" />
                </SelectTrigger>
                <SelectContent>
                  {ROLE_OPTIONS.map((role) => (
                    <SelectItem key={role.value} value={role.value}>
                      {role.label} - {role.description}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Password Reset Section */}
            <div className="border-t pt-4 space-y-2">
              <label className="text-sm font-medium flex items-center gap-2">
                <Key className="h-4 w-4" />
                Reset Password (optional)
              </label>
              <Input
                type="password"
                placeholder="Leave empty to keep current password"
                value={editFormData.newPassword}
                onChange={(e) => setEditFormData({ ...editFormData, newPassword: e.target.value })}
              />
              <p className="text-xs text-muted-foreground">Enter a new password (min 6 characters) to reset</p>
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setEditDialogOpen(false)}>
              Cancel
            </Button>
            <Button
              onClick={handleUpdateUser}
              disabled={actionLoading === "update"}
            >
              {actionLoading === "update" ? (
                <>
                  <RefreshCw className="h-4 w-4 mr-2 animate-spin" />
                  Saving...
                </>
              ) : (
                "Save Changes"
              )}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation Dialog */}
      <Dialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>Delete User</DialogTitle>
            <DialogDescription>
              Are you sure you want to remove {selectedUser?.email}? This action cannot be undone.
            </DialogDescription>
          </DialogHeader>
          <DialogFooter className="gap-2 sm:gap-0">
            <Button variant="outline" onClick={() => setDeleteDialogOpen(false)}>
              Cancel
            </Button>
            <Button
              variant="destructive"
              onClick={handleDeleteUser}
              disabled={actionLoading === "delete"}
            >
              {actionLoading === "delete" ? (
                <>
                  <RefreshCw className="h-4 w-4 mr-2 animate-spin" />
                  Deleting...
                </>
              ) : (
                "Delete User"
              )}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default UsersManager;
